  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Death in Vegas', 'death in vegas', false, 'Death In Vegas is the influential, long-running project of Richard Fearless, a British musician who has spent the last three decades moving between rock, psychedelia and techno with little concern for categorisation. While the group’s early releases sat closer to big beat and band dynamics, later work became increasingly minimal, hypnotic and club-informed (Fearless himself started out as a resident DJ at London’s Job Club in the ’90s). Across their prolific output, including multiple LPs, atmosphere-building and a brooding sense of repetition are ever present. In addition, a mind-blowing roster of collaborators over the years includes Bobby Gillespie, Iggy Pop, The Jesus and Mary Chain’s Jim Reid and Mazzy Star’s Hope Sandoval. This summer, Death In Vegas will perform as part of our Thursday live program.', 'https://dekmantelfestival.com/artists/death-in-vegas', 'festival:dekmantel-2026', 'Death In Vegas is the influential, long-running project of Richard Fearless, a British musician who has spent the last three decades moving between rock, psychedelia and techno with little concern for categorisation. While the group’s early releases sat closer to big beat and band dynamics, later work became increasingly minimal, hypnotic and club-informed (Fearless himself started out as a resident DJ at London’s Job Club in the ’90s). Across their prolific output, including multiple LPs, atmosphere-building and a brooding sense of repetition are ever present. In addition, a mind-blowing roster of collaborators over the years includes Bobby Gillespie, Iggy Pop, The Jesus and Mary Chain’s Jim Reid and Mazzy Star’s Hope Sandoval. This summer, Death In Vegas will perform as part of our Thursday live program.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Darkside', 'darkside', false, 'If we were to make a list of electronic albums that defined the ’10s, DARKSIDE’s ‘Psychic’ would sit very close to the top. Released in 2013, that spellbinding first outing by producer/composer/multi-instrumentalist Nicolas Jaar and guitarist/sound designer Dave Harrington immediately confirmed what we already knew: these are two of the greatest electronic musicians in the game, laying out an entirely new experimental crossroads between psychedelic rock, techno, minimal and jazz-dub. Following a long hiatus, ‘Spiral’ (2021) finally brought new DARKSIDE material into the world, followed by a brilliant live album in 2023. By then, the duo had become a trio, with Tlacael Esparza joining on drums. Renowned for their lush long-form live shows and deep, slow-burning builds, we’re very proud to bring Darkside to Dekmantel Festival for the first time.', 'https://dekmantelfestival.com/artists/darkside', 'festival:dekmantel-2026', 'If we were to make a list of electronic albums that defined the ’10s, DARKSIDE’s ‘Psychic’ would sit very close to the top. Released in 2013, that spellbinding first outing by producer/composer/multi-instrumentalist Nicolas Jaar and guitarist/sound designer Dave Harrington immediately confirmed what we already knew: these are two of the greatest electronic musicians in the game, laying out an entirely new experimental crossroads between psychedelic rock, techno, minimal and jazz-dub. Following a long hiatus, ‘Spiral’ (2021) finally brought new DARKSIDE material into the world, followed by a brilliant live album in 2023. By then, the duo had become a trio, with Tlacael Esparza joining on drums. Renowned for their lush long-form live shows and deep, slow-burning builds, we’re very proud to bring Darkside to Dekmantel Festival for the first time.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Juan Atkins', 'juan atkins', false, 'Few figures loom as large in the history of electronic music as Juan Atkins. Widely regarded as one of the original architects of Detroit techno, the Metroplex founder helped shape a sound that would travel from the Motor City to dancefloors around the world. Through pioneering projects such as Cybotron and Model 500, Atkins fused electro, funk and futurist machine rhythms into a blueprint for modern techno. Decades on, his influence remains immeasurable. As a DJ, he moves fluidly between past and future, threading together the genre’s roots with its ever-evolving possibilities — a reminder that techno’s original vision of science fiction, soul and circuitry still resonates today. In addition to DJing on the RADAR stage, Atkins performs live as Infiniti on Thursday evening, marking 30 years since the release of his debut album under the alias.', 'https://dekmantelfestival.com/artists/juan-atkins', 'festival:dekmantel-2026', 'Few figures loom as large in the history of electronic music as Juan Atkins. Widely regarded as one of the original architects of Detroit techno, the Metroplex founder helped shape a sound that would travel from the Motor City to dancefloors around the world. Through pioneering projects such as Cybotron and Model 500, Atkins fused electro, funk and futurist machine rhythms into a blueprint for modern techno. Decades on, his influence remains immeasurable. As a DJ, he moves fluidly between past and future, threading together the genre’s roots with its ever-evolving possibilities — a reminder that techno’s original vision of science fiction, soul and circuitry still resonates today. In addition to DJing on the RADAR stage, Atkins performs live as Infiniti on Thursday evening, marking 30 years since the release of his debut album under the alias.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Josey Rebelle', 'josey rebelle', false, 'Raised within Caribbean sound system culture, Josey Rebelle started DJing at 13, teaching herself to mix with records from her brother’s vinyl collection. Years of obsessive practice took her from bedroom sessions to the booth at London’s legendary Plastic People, and later to a decade-long run on Rinse FM. Today, she is recognised as one of the world’s most vital selectors. Rebelle’s sets are defined by motion. House mutates into jungle, dub collides with techno, tempos shift in an instant — but the energy never dips. Moving with total freedom across genres, she threads every turn with precision, pressure, and control. Whether in a darkened club or out in the open air, Josey Rebelle knows exactly how to lock into a dancefloor and lead it somewhere unexpected. On Thursday night at Melkweg for Dekmantel ’26, she takes dancers deeper into the afterhours.', 'https://dekmantelfestival.com/artists/josey-rebelle', 'festival:dekmantel-2026', 'Raised within Caribbean sound system culture, Josey Rebelle started DJing at 13, teaching herself to mix with records from her brother’s vinyl collection. Years of obsessive practice took her from bedroom sessions to the booth at London’s legendary Plastic People, and later to a decade-long run on Rinse FM. Today, she is recognised as one of the world’s most vital selectors. Rebelle’s sets are defined by motion. House mutates into jungle, dub collides with techno, tempos shift in an instant — but the energy never dips. Moving with total freedom across genres, she threads every turn with precision, pressure, and control. Whether in a darkened club or out in the open air, Josey Rebelle knows exactly how to lock into a dancefloor and lead it somewhere unexpected. On Thursday night at Melkweg for Dekmantel ’26, she takes dancers deeper into the afterhours.')
