  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Molina', 'molina', false, 'Rebecca Molina is a Copenhagen-based artist working at the intersection of mood-building songwriting, sample-based electronics and hand-played instrumentation. Her fuzzed-out compositions are marked by restraint and precision, drawing on minimal pop structures, dubby spatial logic and a close, unguarded vocal presence. Released through the Escho imprint, Molina’s sounds move with quiet intent between the listening space and the club, focussing on tone, pacing and physical detail rather than grand gestures. This summer, she will make her Dekmantel Festival debut with a Thursday concert.', 'https://dekmantelfestival.com/artists/molina', 'festival:dekmantel-2026', 'Rebecca Molina is a Copenhagen-based artist working at the intersection of mood-building songwriting, sample-based electronics and hand-played instrumentation. Her fuzzed-out compositions are marked by restraint and precision, drawing on minimal pop structures, dubby spatial logic and a close, unguarded vocal presence. Released through the Escho imprint, Molina’s sounds move with quiet intent between the listening space and the club, focussing on tone, pacing and physical detail rather than grand gestures. This summer, she will make her Dekmantel Festival debut with a Thursday concert.')
