  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Headache', 'headache', false, 'Headache is the introspective alias of London producer Joe Thornalley, also known as Vegyn. Where Vegyn leans toward crisp beats and experimental pop, Headache opens up a more fragile, dreamlike terrain. Through ambient sketches, submerged, trip-hop-adjacent melodies, and glitchy fragments, the project coalesces around diaristic lyrics written by Francis Hornsby Clark and performed by AI – an uncanny element that electrifies the music, blurring confession with synthetic performance. Released primarily via the PLZ Make It Ruins label, Headache has cultivated a devoted following for its hazy atmosphere and quietly arresting emotional pull.', 'https://dekmantelfestival.com/artists/headache', 'festival:dekmantel-2026', 'Headache is the introspective alias of London producer Joe Thornalley, also known as Vegyn. Where Vegyn leans toward crisp beats and experimental pop, Headache opens up a more fragile, dreamlike terrain. Through ambient sketches, submerged, trip-hop-adjacent melodies, and glitchy fragments, the project coalesces around diaristic lyrics written by Francis Hornsby Clark and performed by AI – an uncanny element that electrifies the music, blurring confession with synthetic performance. Released primarily via the PLZ Make It Ruins label, Headache has cultivated a devoted following for its hazy atmosphere and quietly arresting emotional pull.')
