    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('New York', 'new york', false, 'Your new favourite band: NEW YORK. The London-based duo – Coumba Samba and Gretchen Lawrence – quickly gained cult attention with their debut album No Sleep Till NY, hailed as one of 2022’s standout discoveries for its icy electro surfaces, body-shaking reggaeton rhythms, and brazenly filthy lyricism. Hot on the heels of their 2025 record Push, a release that pushes their dark, bracing, and deliciously uncanny sound into deeper waters, NEW YORK continue to blur the lines between pop immediacy and experimental intent. Too smart and elusive to sit comfortably inside ''indie revivalist'' narratives, NEW YORK operate on their own terms – where pop, club pressure, and visual art intuition intersect.', 'https://dekmantelfestival.com/artists/new-york', 'festival:dekmantel-2026', 'Your new favourite band: NEW YORK. The London-based duo – Coumba Samba and Gretchen Lawrence – quickly gained cult attention with their debut album No Sleep Till NY, hailed as one of 2022’s standout discoveries for its icy electro surfaces, body-shaking reggaeton rhythms, and brazenly filthy lyricism. Hot on the heels of their 2025 record Push, a release that pushes their dark, bracing, and deliciously uncanny sound into deeper waters, NEW YORK continue to blur the lines between pop immediacy and experimental intent. Too smart and elusive to sit comfortably inside ''indie revivalist'' narratives, NEW YORK operate on their own terms – where pop, club pressure, and visual art intuition intersect.')
