  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Upsammy', 'upsammy', false, 'Spatial, intricate, crystalline, transient – there are many beautiful words to describe the upsammy universe. As a producer and multidisciplinary artist, Thessa Torsing subtly shapes explorative sound worlds in which the digital and organic collide. In 2020, following her ‘Wild Chamber’ breakout on Nous’klaer Audio, the artist’s dreamlike debut album ‘Zoom’ was released on our own imprint. Recently, the Dutch artist returned to Dekmantel Records with the EP ‘Open Catalyst’, which reinforces the clubby side of her special sound world: gleaming, sprightly DnB and high-definition techno in the faster zones, always anchored by a restorative centre. At this point, we cannot imagine Dekmantel Festival without upsammy present to tickle our brain cells.', 'https://dekmantelfestival.com/artists/upsammy-2', 'festival:dekmantel-2026', 'Spatial, intricate, crystalline, transient – there are many beautiful words to describe the upsammy universe. As a producer and multidisciplinary artist, Thessa Torsing subtly shapes explorative sound worlds in which the digital and organic collide. In 2020, following her ‘Wild Chamber’ breakout on Nous’klaer Audio, the artist’s dreamlike debut album ‘Zoom’ was released on our own imprint. Recently, the Dutch artist returned to Dekmantel Records with the EP ‘Open Catalyst’, which reinforces the clubby side of her special sound world: gleaming, sprightly DnB and high-definition techno in the faster zones, always anchored by a restorative centre. At this point, we cannot imagine Dekmantel Festival without upsammy present to tickle our brain cells.')
