  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Piezo & Upsammy present Eerie Enterprise', 'piezo & upsammy present eerie enterprise', false, 'Familiar faces on the Amsterdamse Bos grounds and label artists, upsammy and Piezo join forces for a new live performance as Eerie Enterprise, showcasing their upcoming project on Dekmantel Records. Amsterdam-based upsammy is known for blending hyper-detailed sound design with organic textures, releasing on Dekmantel Records as well as PAN, and extending her practice into visuals and her NTS show Pacing the Platform. Her club-facing sound, gleaming DnB and high-definition techno balances speed with a restorative core. Milan-based Piezo brings cybernetic techno to life with wonky, off-kilter textures and emotive melodies. A UFO Series standout and the force behind Ansia, he explores experimental club music rooted in soundsystem culture. See what unfolds when their two universes collide at Dekmantel 2026.', 'https://dekmantelfestival.com/artists/eerie-enterprise-piezo-upsammy-live', 'festival:dekmantel-2026', 'Familiar faces on the Amsterdamse Bos grounds and label artists, upsammy and Piezo join forces for a new live performance as Eerie Enterprise, showcasing their upcoming project on Dekmantel Records. Amsterdam-based upsammy is known for blending hyper-detailed sound design with organic textures, releasing on Dekmantel Records as well as PAN, and extending her practice into visuals and her NTS show Pacing the Platform. Her club-facing sound, gleaming DnB and high-definition techno balances speed with a restorative core. Milan-based Piezo brings cybernetic techno to life with wonky, off-kilter textures and emotive melodies. A UFO Series standout and the force behind Ansia, he explores experimental club music rooted in soundsystem culture. See what unfolds when their two universes collide at Dekmantel 2026.')
