  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Aurora Halal', 'aurora halal', false, 'If you’ve set foot on Dekmantel ground before, chances are you’ve felt it being shaken by Aurora Halal. This Brooklyn‑based favourite runs the respected Mutual Dreaming party series and the like-minded festival Sustain-Release. As a producer and DJ, with regular appearances at Berghain and, previously, at De School, Aurora Halal has developed a shadowy, psychedelic style that melds techno subgenres together through experimental textures and dreamy, detailed soundscapes. She’s the kind of artist whose sonic journeys equally cater to body and mind, leaving you both breathless and wonderfully fulfilled.', 'https://dekmantelfestival.com/artists/aurora-halal', 'festival:dekmantel-2026', 'If you’ve set foot on Dekmantel ground before, chances are you’ve felt it being shaken by Aurora Halal. This Brooklyn‑based favourite runs the respected Mutual Dreaming party series and the like-minded festival Sustain-Release. As a producer and DJ, with regular appearances at Berghain and, previously, at De School, Aurora Halal has developed a shadowy, psychedelic style that melds techno subgenres together through experimental textures and dreamy, detailed soundscapes. She’s the kind of artist whose sonic journeys equally cater to body and mind, leaving you both breathless and wonderfully fulfilled.')
