  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Speedy J', 'speedy j', false, 'Jochem George Paap is a foundational force in Dutch techno and far beyond. Active since the early ’90s, seminal Speedy J albums like Ginger and G‑Spot established him as one of Europe’s pioneering techno producers. While his work has always remained rooted in the robust Rotterdam sound, over the years he has also toyed with the more abstract – constantly exploring new creative terrain and adjacent genres such as ambient and industrial. Speedy J is also the founder of STOOR, an improv-focussed electronic lab and label dedicated to musical, visual, and technological experimentation, and home to his collaborations with artists like Surgeon and Steve Rachmad.', 'https://dekmantelfestival.com/artists/speedy-j', 'festival:dekmantel-2026', 'Jochem George Paap is a foundational force in Dutch techno and far beyond. Active since the early ’90s, seminal Speedy J albums like Ginger and G‑Spot established him as one of Europe’s pioneering techno producers. While his work has always remained rooted in the robust Rotterdam sound, over the years he has also toyed with the more abstract – constantly exploring new creative terrain and adjacent genres such as ambient and industrial. Speedy J is also the founder of STOOR, an improv-focussed electronic lab and label dedicated to musical, visual, and technological experimentation, and home to his collaborations with artists like Surgeon and Steve Rachmad.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('SNPLO', 'snplo', false, 'Artist Profiles - Dekmantel Festival NEWSnPLO is the collaborative project of Canadian artists SnP 500 and Berlin-based producer PLO Man, operating at the crossroads of dubby techno, loop-based experimentation and process-driven club music. Rooted in hardware workflows and a shared fascination with repetition and gradual mutation, SnPLO’s releases distil techno to its most transcendental elements: deep, dense, exploratory and expansive. For Dekmantel Festival 2026, they bring this approach to the upstairs room of Paradiso, where STOOR is hosting its acclaimed live-improv session. Expect loops pushed beyond their limits, and techno emerging in the moment.', 'https://dekmantelfestival.com/artists/snplo-live', 'festival:dekmantel-2026', 'Artist Profiles - Dekmantel Festival NEWSnPLO is the collaborative project of Canadian artists SnP 500 and Berlin-based producer PLO Man, operating at the crossroads of dubby techno, loop-based experimentation and process-driven club music. Rooted in hardware workflows and a shared fascination with repetition and gradual mutation, SnPLO’s releases distil techno to its most transcendental elements: deep, dense, exploratory and expansive. For Dekmantel Festival 2026, they bring this approach to the upstairs room of Paradiso, where STOOR is hosting its acclaimed live-improv session. Expect loops pushed beyond their limits, and techno emerging in the moment.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Nala Brown', 'nala brown', false, 'It’s often easy to tell if a DJ loves dancing by the way they play and the energy they bring to a room. Jacqueline Monteiro, who goes by the moniker Nala Brown, is one of those DJs who makes it hard to stay still whenever she steps into the booth. Her sets are an eclectic blend of tracks by Detroit legends, New York’s new generation of club music producers, edits of her favourite contemporary pop and R&B stars, and a generous dose of high‑energy percussion. While often tapping into her Cape Verdean roots, Nala Brown was born and raised in Rotterdam, where she has organised various parties and hosted community talks with the all-femme AMPFEMININE nightlife collective.', 'https://dekmantelfestival.com/artists/nala-brown', 'festival:dekmantel-2026', 'It’s often easy to tell if a DJ loves dancing by the way they play and the energy they bring to a room. Jacqueline Monteiro, who goes by the moniker Nala Brown, is one of those DJs who makes it hard to stay still whenever she steps into the booth. Her sets are an eclectic blend of tracks by Detroit legends, New York’s new generation of club music producers, edits of her favourite contemporary pop and R&B stars, and a generous dose of high‑energy percussion. While often tapping into her Cape Verdean roots, Nala Brown was born and raised in Rotterdam, where she has organised various parties and hosted community talks with the all-femme AMPFEMININE nightlife collective.')
