  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Identified Patient', 'identified patient', false, 'Identified Patient, aka Job Veerman, stands as one of the Netherlands’ most vital underground DJs and producers. Renowned for high-voltage sets that crackle and spark, moving lithely between techno, bass, acid, wave, and industrial, his sound carries a dark romanticism, thriving on tension and controlled chaos. A long-standing Dekmantel favourite, Veerman returned to the label in 2025 for the third time with Reset, a future-facing EP that pairs crushing low-end frequencies with razor-sharp precision. Across further releases on Dekmantel and his own Nerve Collect imprint, co-run with Gamma Intel, Identified Patient delivers club music that is bold and unapologetically physical – engineered to unsettle and seduce in equal measure.', 'https://dekmantelfestival.com/artists/identified-patient', 'festival:dekmantel-2026', 'Identified Patient, aka Job Veerman, stands as one of the Netherlands’ most vital underground DJs and producers. Renowned for high-voltage sets that crackle and spark, moving lithely between techno, bass, acid, wave, and industrial, his sound carries a dark romanticism, thriving on tension and controlled chaos. A long-standing Dekmantel favourite, Veerman returned to the label in 2025 for the third time with Reset, a future-facing EP that pairs crushing low-end frequencies with razor-sharp precision. Across further releases on Dekmantel and his own Nerve Collect imprint, co-run with Gamma Intel, Identified Patient delivers club music that is bold and unapologetically physical – engineered to unsettle and seduce in equal measure.')
  ON CONFLICT (sort_name) DO UPDATE SET
