  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Skrillex', 'skrillex', false, 'Sonny John Moore – better known as Skrillex – has built a career few can rival: MTV’s Electronic Dance Music Artist of the Year and the distinction of being the most awarded electronic artist in Grammy history. Rising to prominence during the early-2010s explosion of dubstep, he helped push the sound into the global mainstream before years of restless reinvention across pop, rap, and club music. More recently, he has turned his attention back toward the underground, collaborating with boundary-pushing artists such as RHR and Slikback while exploring rawer textures and bass mutations – all without losing his signature bombastic style. He makes his Dekmantel debut in ’26 – and it’s a double helping; don’t miss a special B2B with RHR happening the same day.', 'https://dekmantelfestival.com/artists/skrillex', 'festival:dekmantel-2026', 'Sonny John Moore – better known as Skrillex – has built a career few can rival: MTV’s Electronic Dance Music Artist of the Year and the distinction of being the most awarded electronic artist in Grammy history. Rising to prominence during the early-2010s explosion of dubstep, he helped push the sound into the global mainstream before years of restless reinvention across pop, rap, and club music. More recently, he has turned his attention back toward the underground, collaborating with boundary-pushing artists such as RHR and Slikback while exploring rawer textures and bass mutations – all without losing his signature bombastic style. He makes his Dekmantel debut in ’26 – and it’s a double helping; don’t miss a special B2B with RHR happening the same day.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('RHR & Skrillex', 'rhr & skrillex', false, 'From setting the floor on fire at Selectors to releasing blazing sounds on our record label, RHR has firmly earned his place in the Dekmantel family. He stands among a new wave of Brazilian artists dissolving the false divide between the country’s dominant club circuits and the favela-born force of baile funk. Rooted in São Paulo yet resonating worldwide, RHR fuses street-level intensity with rave pressure. That momentum recently carried him into the studio with Skrillex, contributing to the latter’s forthcoming album. As for Skrillex, his Dekmantel debut needs little framing: a producer who helped redefine dubstep’s mainstream moment, before years of restless shape-shifting across pop, rap, experimental electronics, and beyond. Expect a high-impact set that moves fast, hits hard, and refuses to sit still.', 'https://dekmantelfestival.com/artists/rhr-skrillex', 'festival:dekmantel-2026', 'From setting the floor on fire at Selectors to releasing blazing sounds on our record label, RHR has firmly earned his place in the Dekmantel family. He stands among a new wave of Brazilian artists dissolving the false divide between the country’s dominant club circuits and the favela-born force of baile funk. Rooted in São Paulo yet resonating worldwide, RHR fuses street-level intensity with rave pressure. That momentum recently carried him into the studio with Skrillex, contributing to the latter’s forthcoming album. As for Skrillex, his Dekmantel debut needs little framing: a producer who helped redefine dubstep’s mainstream moment, before years of restless shape-shifting across pop, rap, experimental electronics, and beyond. Expect a high-impact set that moves fast, hits hard, and refuses to sit still.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Sherelle', 'sherelle', false, 'In case you missed it, ’25 was the year that SHERELLE (yes, all caps) released her debut record, WITH A VENGEANCE (also all caps). Much like the London artist’s DJ sets – who remembers that iconic closing at The Nest in ’22 or the B2B session with RP Boo in ’24 – her album races through high‑speed dance genres, from DnB, jungle and footwork to acid, techno and hardcore. Add in her meticulously dosed sample chops, vocal percussion and revved-up breaks, and the result is a frenetic, over-the-top joyride (velocity 160+ BPM, emergency brakes non-existent) that you dared yourself to get on – and now can’t get off. All you can do is take a deep breath and embrace the system-shaking thrill.', 'https://dekmantelfestival.com/artists/sherelle', 'festival:dekmantel-2026', 'In case you missed it, ’25 was the year that SHERELLE (yes, all caps) released her debut record, WITH A VENGEANCE (also all caps). Much like the London artist’s DJ sets – who remembers that iconic closing at The Nest in ’22 or the B2B session with RP Boo in ’24 – her album races through high‑speed dance genres, from DnB, jungle and footwork to acid, techno and hardcore. Add in her meticulously dosed sample chops, vocal percussion and revved-up breaks, and the result is a frenetic, over-the-top joyride (velocity 160+ BPM, emergency brakes non-existent) that you dared yourself to get on – and now can’t get off. All you can do is take a deep breath and embrace the system-shaking thrill.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Skin on Skin', 'skin on skin', false, 'Big emotions, cheeky edits, and grooves that refuse to behave: this is Skin On Skin in full effect. The South Sudanese-Australian DJ slams together techno, house, and UK drill-inflected hip-hop, crafting a high-impact medley that’s as playful as it is propulsive. His sets thrive on contrast – sudden switches, sticky hooks, and jammy basslines that flirt with chaos. Rising from Brisbane to international stages, he has released on labels including Stay On Sight Recordings, most notably Home Is True – a mixtape of new and old songs that captures his restless, diaristic approach to club music. Known for earworm tracks like “Burn Dem Bridges” – all bruised vocals and swaggering low-end – alongside electric back-to-backs with Skillrex, close collaborator Mall Grab, and others, Skin On Skin turns reckless joy into a finely tuned dancefloor weapon.', 'https://dekmantelfestival.com/artists/skin-on-skin', 'festival:dekmantel-2026', 'Big emotions, cheeky edits, and grooves that refuse to behave: this is Skin On Skin in full effect. The South Sudanese-Australian DJ slams together techno, house, and UK drill-inflected hip-hop, crafting a high-impact medley that’s as playful as it is propulsive. His sets thrive on contrast – sudden switches, sticky hooks, and jammy basslines that flirt with chaos. Rising from Brisbane to international stages, he has released on labels including Stay On Sight Recordings, most notably Home Is True – a mixtape of new and old songs that captures his restless, diaristic approach to club music. Known for earworm tracks like “Burn Dem Bridges” – all bruised vocals and swaggering low-end – alongside electric back-to-backs with Skillrex, close collaborator Mall Grab, and others, Skin On Skin turns reckless joy into a finely tuned dancefloor weapon.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Beste Hira', 'beste hira', false, 'Classically trained musician Beste Hira brings a deep grasp of craft to the decks. After reaching conservatory level in cello and piano, she pivoted to pursue her calling as a DJ, carrying years of study directly into the club. Behind the turntables, her extensive musical grounding is palpable: she meticulously experiments with sound, guided by an intuition that allows her to push boldly beyond familiar terrain. Originally from Istanbul and now based in Amsterdam, Hira channels the hypnotic, fast-paced, and darker edges of techno with precision and intent. The result is a full-bodied, immersive journey – intense, considered, and vividly alive to the moment.', 'https://dekmantelfestival.com/artists/beste-hira', 'festival:dekmantel-2026', 'Classically trained musician Beste Hira brings a deep grasp of craft to the decks. After reaching conservatory level in cello and piano, she pivoted to pursue her calling as a DJ, carrying years of study directly into the club. Behind the turntables, her extensive musical grounding is palpable: she meticulously experiments with sound, guided by an intuition that allows her to push boldly beyond familiar terrain. Originally from Istanbul and now based in Amsterdam, Hira channels the hypnotic, fast-paced, and darker edges of techno with precision and intent. The result is a full-bodied, immersive journey – intense, considered, and vividly alive to the moment.')
