  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Dr. Rubinstein & Ellen Allien', 'dr. rubinstein & ellen allien', false, 'If you were to list Berlin’s techno matriarchs, two names that would certainly pop up are Ellen Allien and Dr. Rubinstein. While Ellen Allien (real name: Ellen Fraatz) has been shaping the soundscape since the ’90s as a producer, DJ and label founder Dr. Rubinstein (real name: Marina Rubinstein) has carried that spirit through the ’10s and ’20s. Both artists are celebrated for their long, authentic, high-energy journeys behind the decks – blending immersive contemporary techno and acid with a raw, playful dose of nostalgia. Don’t miss this intergenerational B2B.', 'https://dekmantelfestival.com/artists/dr-rubinstein-ellen-allien', 'festival:dekmantel-2026', 'If you were to list Berlin’s techno matriarchs, two names that would certainly pop up are Ellen Allien and Dr. Rubinstein. While Ellen Allien (real name: Ellen Fraatz) has been shaping the soundscape since the ’90s as a producer, DJ and label founder Dr. Rubinstein (real name: Marina Rubinstein) has carried that spirit through the ’10s and ’20s. Both artists are celebrated for their long, authentic, high-energy journeys behind the decks – blending immersive contemporary techno and acid with a raw, playful dose of nostalgia. Don’t miss this intergenerational B2B.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Dax J', 'dax j', false, 'Stripping techno down to its rawest elements – rhythm, repetition, and release – Dax J’s intense, industrial-leaning sound is unmistakably his own. Headlining institutions such as Berghain and Bassiani, the London-born artist rose from the underground to global prominence, earning accolades from Resident Advisor, DJ Mag, and Groove Magazine along the way. Across records released on his own Monnom Black imprint – including the celebrated albums Shades of Black and Offending Public Morality – he has consistently pushed the form forward. In his live shows, relentless productions driven by distorted percussion blur the line between performance and pressure test, locking dancers into a hypnotic, high-tempo momentum. Fierce, focused, and utterly face-melting, this live set marks Dax J’s first in the Netherlands for eight years. His performance is also a brand-new live show – experienced here at Dekmantel for the very first time.', 'https://dekmantelfestival.com/artists/dax-j-live', 'festival:dekmantel-2026', 'Stripping techno down to its rawest elements – rhythm, repetition, and release – Dax J’s intense, industrial-leaning sound is unmistakably his own. Headlining institutions such as Berghain and Bassiani, the London-born artist rose from the underground to global prominence, earning accolades from Resident Advisor, DJ Mag, and Groove Magazine along the way. Across records released on his own Monnom Black imprint – including the celebrated albums Shades of Black and Offending Public Morality – he has consistently pushed the form forward. In his live shows, relentless productions driven by distorted percussion blur the line between performance and pressure test, locking dancers into a hypnotic, high-tempo momentum. Fierce, focused, and utterly face-melting, this live set marks Dax J’s first in the Netherlands for eight years. His performance is also a brand-new live show – experienced here at Dekmantel for the very first time.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Katatonic Silentio', 'katatonic silentio', false, 'Behind the Katatonic Silentio project is Mariachiara Troianiello, an Italian sound artist and researcher working across electronic music, performance and sound studies. Both as a live performer/producer and independent researcher, her practice moves between disciplines and approaches to sonic production. Active as a DJ for two decades, her sets range from abstract musique concrète through spoken word, ambient and dub, to more club-oriented forms including techno, industrial and DnB. With Katatonic Silentio – coming to Dekmantel Festival for the first time – Troianiello zooms in on the severe zone between techno, industrial, noise and sound art, prioritising texture, tension and negative space over club-functional rhythms.', 'https://dekmantelfestival.com/artists/katatonic-silentio', 'festival:dekmantel-2026', 'Behind the Katatonic Silentio project is Mariachiara Troianiello, an Italian sound artist and researcher working across electronic music, performance and sound studies. Both as a live performer/producer and independent researcher, her practice moves between disciplines and approaches to sonic production. Active as a DJ for two decades, her sets range from abstract musique concrète through spoken word, ambient and dub, to more club-oriented forms including techno, industrial and DnB. With Katatonic Silentio – coming to Dekmantel Festival for the first time – Troianiello zooms in on the severe zone between techno, industrial, noise and sound art, prioritising texture, tension and negative space over club-functional rhythms.')
