    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Dino Sabatini & Luigi Tozzi', 'dino sabatini & luigi tozzi', false, 'Bringing their iconic collaboration to the Netherlands for the very first time, Dino Sabatini and Luigi Tozzi are a match made in heaven. While Sabatini is a veteran figure in Italian techno, active since the late 1990s, Tozzi emerged a decade later, quickly establishing himself as a force in his own right. Bridging generations, the pair share a devotion to slow-burn intensity, sculpted low frequencies, and a meticulous sense of spatial control. Drawing from dub techno, ambient pressure, and sci-fi futurism, their sound unfolds patiently, with atmosphere and physical weight held in constant dialogue. Rather than chasing peaks, Sabatini and Tozzi construct immersive, long-form journeys – hypnotic, subterranean, and absorbing – designed to pull listeners inward and keep them there.', 'https://dekmantelfestival.com/artists/luigi-tozzi-dino-sabbatini-live', 'festival:dekmantel-2026', 'Bringing their iconic collaboration to the Netherlands for the very first time, Dino Sabatini and Luigi Tozzi are a match made in heaven. While Sabatini is a veteran figure in Italian techno, active since the late 1990s, Tozzi emerged a decade later, quickly establishing himself as a force in his own right. Bridging generations, the pair share a devotion to slow-burn intensity, sculpted low frequencies, and a meticulous sense of spatial control. Drawing from dub techno, ambient pressure, and sci-fi futurism, their sound unfolds patiently, with atmosphere and physical weight held in constant dialogue. Rather than chasing peaks, Sabatini and Tozzi construct immersive, long-form journeys – hypnotic, subterranean, and absorbing – designed to pull listeners inward and keep them there.')
  ON CONFLICT (sort_name) DO UPDATE SET
