  INSERT INTO artists (name, sort_name, is_collective)
  VALUES ('Sybil', 'sybil', false)
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Garçon & Sybil', 'garçon & sybil', false, 'Pressure and smouldering restraint – this is the art of the slow burn. Garçon’s finely tuned, hypnotic sonic language – patient, volatile, and atmospheric – interlaces with Sybil’s genre-fluid storytelling and expansive sense of space. Moving between deep dub, techno propulsion, hazy breaks, and trance-inflected euphoria, this pairing privileges journey over immediacy – an approach rooted in both artists’ long-term commitments to immersive, narrative-driven DJing. Co-founder of the influential label Amenthia, Garçon is a resident at Japan’s Transcendence Festival, while London-based Sybil’s global presence spans Sustain Release, Waking Life, Nowadays, Paral·lel Butik, Miscellania in Melbourne, vurt in Seoul, Discos Movimiento in Mexico City and more, alongside her work curating the much-adored ambient mix series Deep Mind Music.', 'https://dekmantelfestival.com/artists/garçon-sybil', 'festival:dekmantel-2026', 'Pressure and smouldering restraint – this is the art of the slow burn. Garçon’s finely tuned, hypnotic sonic language – patient, volatile, and atmospheric – interlaces with Sybil’s genre-fluid storytelling and expansive sense of space. Moving between deep dub, techno propulsion, hazy breaks, and trance-inflected euphoria, this pairing privileges journey over immediacy – an approach rooted in both artists’ long-term commitments to immersive, narrative-driven DJing. Co-founder of the influential label Amenthia, Garçon is a resident at Japan’s Transcendence Festival, while London-based Sybil’s global presence spans Sustain Release, Waking Life, Nowadays, Paral·lel Butik, Miscellania in Melbourne, vurt in Seoul, Discos Movimiento in Mexico City and more, alongside her work curating the much-adored ambient mix series Deep Mind Music.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Mike Parker', 'mike parker', false, 'Mike Parker is, as you might expect, a perfectionist. His take on techno is meticulous, his grooves as hypnotic as any. Over the course of three decades, the American DJ – who started out playing warehouse parties in the mid-1990s – has honed his vision with ever-increasing precision. As a producer, he packs remarkable amounts of detail into his tracks, elevating them far beyond purely functional material. That approach has seen his music released on labels such as Semantica, Tresor, Spazio Disponibile and Field Records, alongside his own imprint, Geophone. It’s been almost 10 years since this club veteran last joined us in the festival forest, and we’re thrilled to welcome him back for a live set.', 'https://dekmantelfestival.com/artists/mike-parker-live', 'festival:dekmantel-2026', 'Mike Parker is, as you might expect, a perfectionist. His take on techno is meticulous, his grooves as hypnotic as any. Over the course of three decades, the American DJ – who started out playing warehouse parties in the mid-1990s – has honed his vision with ever-increasing precision. As a producer, he packs remarkable amounts of detail into his tracks, elevating them far beyond purely functional material. That approach has seen his music released on labels such as Semantica, Tresor, Spazio Disponibile and Field Records, alongside his own imprint, Geophone. It’s been almost 10 years since this club veteran last joined us in the festival forest, and we’re thrilled to welcome him back for a live set.')
  ON CONFLICT (sort_name) DO UPDATE SET
