  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Polygonia', 'polygonia', false, 'The alter ego of multidisciplinary artist Lindsey Wang, Polygonia seamlessly blends elements of techno, downtempo and ambient. Inspired by the natural world and informed by a deep understanding of music theory and instrumentation, her sound brims with intricate, organic shapes and mystical atmospheres. At Dekmantel 2026, Polygonia appears in an extraordinary double billing: a B2B with fellow Berlin mainstay Efdemin and a solo set on RADAR, showcasing her uniquely sculptural approach to rhythm and atmosphere in full.', 'https://dekmantelfestival.com/artists/polygonia', 'festival:dekmantel-2026', 'The alter ego of multidisciplinary artist Lindsey Wang, Polygonia seamlessly blends elements of techno, downtempo and ambient. Inspired by the natural world and informed by a deep understanding of music theory and instrumentation, her sound brims with intricate, organic shapes and mystical atmospheres. At Dekmantel 2026, Polygonia appears in an extraordinary double billing: a B2B with fellow Berlin mainstay Efdemin and a solo set on RADAR, showcasing her uniquely sculptural approach to rhythm and atmosphere in full.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Efdemin & Polygonia', 'efdemin & polygonia', false, 'Efdemin and Polygonia both tread techno’s trippiest realms. No newcomers to Dekmantel, both artists have played the festival on multiple unforgettable occasions. Last year, on the heels of her brilliant ‘Dream Horizons’ release, Polygonia delivered a live set that merged kinetic rhythms, ambient textures, and a super sensitive approach to the grooves that define the dance floor. Efdemin, meanwhile, wrapped the UFO I hangar in stripped yet highly impactful sounds – from the minimal to the lush, from the dreamy to the dark and throbbing. At Dekmantel ’26, these brainy Berlin superpowers are joining forces.', 'https://dekmantelfestival.com/artists/efdemin-polygonia', 'festival:dekmantel-2026', 'Efdemin and Polygonia both tread techno’s trippiest realms. No newcomers to Dekmantel, both artists have played the festival on multiple unforgettable occasions. Last year, on the heels of her brilliant ‘Dream Horizons’ release, Polygonia delivered a live set that merged kinetic rhythms, ambient textures, and a super sensitive approach to the grooves that define the dance floor. Efdemin, meanwhile, wrapped the UFO I hangar in stripped yet highly impactful sounds – from the minimal to the lush, from the dreamy to the dark and throbbing. At Dekmantel ’26, these brainy Berlin superpowers are joining forces.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Nídia', 'nídia', false, 'Raised in Vale da Amoreira, Portugal, Nídia came of age surrounded by the Lusophone African community’s rhythmic traditions and DIY street sound systems. Drawing in particular on kuduro – the high-energy Angolan dance music driven by fast tempos and hard percussion – she pushes decisively toward new sonic futures: fractured, forceful, and fiercely alive. As a key artist within Príncipe Discos, the Lisbon-based label and collective central to Afro-Portuguese club culture, Nídia has helped redefine how grassroots scenes reverberate internationally. Both her productions and DJ sets are agile and uncompromising, built on syncopated beats, sudden drops, and relentless forward motion – rooted in the hyper-local yet primed for dancefloors worldwide.', 'https://dekmantelfestival.com/artists/nídia', 'festival:dekmantel-2026', 'Raised in Vale da Amoreira, Portugal, Nídia came of age surrounded by the Lusophone African community’s rhythmic traditions and DIY street sound systems. Drawing in particular on kuduro – the high-energy Angolan dance music driven by fast tempos and hard percussion – she pushes decisively toward new sonic futures: fractured, forceful, and fiercely alive. As a key artist within Príncipe Discos, the Lisbon-based label and collective central to Afro-Portuguese club culture, Nídia has helped redefine how grassroots scenes reverberate internationally. Both her productions and DJ sets are agile and uncompromising, built on syncopated beats, sudden drops, and relentless forward motion – rooted in the hyper-local yet primed for dancefloors worldwide.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Nicolini', 'nicolini', false, 'Somewhere in the DIY territory between dubby wave, mutant dancehall, low-slung steppers and 180-bpm experiments, you’ll find Nicolini. A project by Nic Mauskovic – also known for The Mauskovic Dance Band and as one half of Devon Rexi – Nicolini is the type of act you’d expect to soundtrack the disco in a David Lynch epoch, were it filmed in the 2020s. This summer, you’re invited to step into a live version of his sonic fever dreams: pleasantly hazy with no intent of clarifying themselves.', 'https://dekmantelfestival.com/artists/nicolini-live', 'festival:dekmantel-2026', 'Somewhere in the DIY territory between dubby wave, mutant dancehall, low-slung steppers and 180-bpm experiments, you’ll find Nicolini. A project by Nic Mauskovic – also known for The Mauskovic Dance Band and as one half of Devon Rexi – Nicolini is the type of act you’d expect to soundtrack the disco in a David Lynch epoch, were it filmed in the 2020s. This summer, you’re invited to step into a live version of his sonic fever dreams: pleasantly hazy with no intent of clarifying themselves.')
