  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('James Massiah & Lord Tusk', 'james massiah & lord tusk', false, 'Dub poet meets seismic beatmaker. James Massiah’s ice-cold, razor-edged delivery rides Lord Tusk’s stripped-back, swaggering productions – raw steppers built from heavyweight drums, dubbed-out synths, and just enough space for verses to land with sharp focus: deadpan, confrontational, darkly playful. Both artists emerged from London’s fertile overlap of club culture and DIY electronics. Massiah cut his teeth in spoken-word circuits and underground music scenes, while also shaping the abrasive, politicised edge of Babyfather (Dean Blunt’s experimental music project); Lord Tusk developed his sound through dub, house, and leftfield, dance-leaning records released on labels such as The Trilogy Tapes. Together, they deal in minimal means and maximum presence – language as melody, rhythm as attitude.', 'https://dekmantelfestival.com/artists/james-massiah-lord-tusk', 'festival:dekmantel-2026', 'Dub poet meets seismic beatmaker. James Massiah’s ice-cold, razor-edged delivery rides Lord Tusk’s stripped-back, swaggering productions – raw steppers built from heavyweight drums, dubbed-out synths, and just enough space for verses to land with sharp focus: deadpan, confrontational, darkly playful. Both artists emerged from London’s fertile overlap of club culture and DIY electronics. Massiah cut his teeth in spoken-word circuits and underground music scenes, while also shaping the abrasive, politicised edge of Babyfather (Dean Blunt’s experimental music project); Lord Tusk developed his sound through dub, house, and leftfield, dance-leaning records released on labels such as The Trilogy Tapes. Together, they deal in minimal means and maximum presence – language as melody, rhythm as attitude.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('T.No', 't.no', false, 'Valentino Shakison, better known as T.NO, is one of the freshest producers to emerge from Amsterdam right now. Specialising in speedy, physical club workouts, he blends his Surinamese roots with global dance influences such as gqom, grime, kuduro, bubbling, kawina, and funk carioca. The key ingredients? Rhythm, energy and dynamic flow, channelled through raw percussion and deep bass. Influential labels such as TraTraTrax have already picked up T.NO’s productions, and 2026 promises the release of his debut full-length record – as well as his Dekmantel debut.', 'https://dekmantelfestival.com/artists/t-no', 'festival:dekmantel-2026', 'Valentino Shakison, better known as T.NO, is one of the freshest producers to emerge from Amsterdam right now. Specialising in speedy, physical club workouts, he blends his Surinamese roots with global dance influences such as gqom, grime, kuduro, bubbling, kawina, and funk carioca. The key ingredients? Rhythm, energy and dynamic flow, channelled through raw percussion and deep bass. Influential labels such as TraTraTrax have already picked up T.NO’s productions, and 2026 promises the release of his debut full-length record – as well as his Dekmantel debut.')
