  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Olof Dreijer & Toya Delazy', 'olof dreijer & toya delazy', false, 'For the first time, Olof Dreijer and Toya Delazy appear together in what is set to be one of the most electrifying – and exclusive – moments of Dekmantel 2026. Dreijer is perhaps best recognised as one half of The Knife, the legendary pop group that reshaped electronic music in the 2000s; his solo output refines that legacy into skewed, percussive club constructions, most recently on Iris, his second EP for the Dekmantel label. A London-based South African artist from KwaZulu-Natal, Toya Delazy operates through her self-defined Afro-rave sound, weaving techno, drum & bass, and beat-driven structures with Zulu lyricism. This debut collaboration unfolds without precedent – an encounter powered by risk, immediacy, and the charge of the unknown.', 'https://dekmantelfestival.com/artists/olof-dreijer-toya-delazy', 'festival:dekmantel-2026', 'For the first time, Olof Dreijer and Toya Delazy appear together in what is set to be one of the most electrifying – and exclusive – moments of Dekmantel 2026. Dreijer is perhaps best recognised as one half of The Knife, the legendary pop group that reshaped electronic music in the 2000s; his solo output refines that legacy into skewed, percussive club constructions, most recently on Iris, his second EP for the Dekmantel label. A London-based South African artist from KwaZulu-Natal, Toya Delazy operates through her self-defined Afro-rave sound, weaving techno, drum & bass, and beat-driven structures with Zulu lyricism. This debut collaboration unfolds without precedent – an encounter powered by risk, immediacy, and the charge of the unknown.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Jyoty', 'jyoty', false, 'If anyone came, saw, and conquered the RADAR stage at Dekmantel Festival’s 10th edition, it’s Jyoty (just head to YouTube for the proof). Born in Amsterdam but rising to prominence via London, the ascent of this super-skilled selector – from online radio and local clubs to sold-out world tours – has been a joy to witness. It surely has something to do with the pure joy Jyoty Singh exudes behind the decks, where she jumbles global elements of bass, breaks, hip-hop, funk, grime, dancehall and more. This summer, the newly crowned star steps out of the streaming arena and onto our big festival stage.', 'https://dekmantelfestival.com/artists/jyoty', 'festival:dekmantel-2026', 'If anyone came, saw, and conquered the RADAR stage at Dekmantel Festival’s 10th edition, it’s Jyoty (just head to YouTube for the proof). Born in Amsterdam but rising to prominence via London, the ascent of this super-skilled selector – from online radio and local clubs to sold-out world tours – has been a joy to witness. It surely has something to do with the pure joy Jyoty Singh exudes behind the decks, where she jumbles global elements of bass, breaks, hip-hop, funk, grime, dancehall and more. This summer, the newly crowned star steps out of the streaming arena and onto our big festival stage.')
