  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Rozaly', 'rozaly', false, 'Rozaly is a Curaçao-born sound artist, researcher and DJ, who came up through Amsterdam’s electronic scene. Blending Caribbean sounds into a contemporary club context, he challenges traditional ideas surrounding his roots while expanding and toying with cultural narratives. Having previously joined us for Dekmantel Festival, Selectors and Lentekabinet, we likely don’t have to tell you what a DJ-set by this whiz entails: blazing percussion, life-size chants and global rhythms – underscored by bass, bass and more bass. If you’re looking for a party, Rozaly is (always) the way to go.', 'https://dekmantelfestival.com/artists/rozaly', 'festival:dekmantel-2026', 'Rozaly is a Curaçao-born sound artist, researcher and DJ, who came up through Amsterdam’s electronic scene. Blending Caribbean sounds into a contemporary club context, he challenges traditional ideas surrounding his roots while expanding and toying with cultural narratives. Having previously joined us for Dekmantel Festival, Selectors and Lentekabinet, we likely don’t have to tell you what a DJ-set by this whiz entails: blazing percussion, life-size chants and global rhythms – underscored by bass, bass and more bass. If you’re looking for a party, Rozaly is (always) the way to go.')
