  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Dekmantel Soundsystem', 'dekmantel soundsystem', false, 'We might be biased, but Dekmantel Soundsystem is Amsterdam’s groove engine. Two selectors, one seamless conversation between eras, genres, and energy. Now powered by Casper Tielrooij and Interstellar Funk, the duo embodies the city’s musical spirit: history-minded but forward-thinking and impossible to pin down. Their sets are adventures built on tension and texture where deep house can melt into dubby techno or EBM grit meets cosmic funk. No gimmicks, just pure dialogue between two storytellers who balance risk with reward. For this set, they will be joined by a selection of friends for even more unpredictable fun.', 'https://dekmantelfestival.com/artists/dekmantel-soundsystem', 'festival:dekmantel-2026', 'We might be biased, but Dekmantel Soundsystem is Amsterdam’s groove engine. Two selectors, one seamless conversation between eras, genres, and energy. Now powered by Casper Tielrooij and Interstellar Funk, the duo embodies the city’s musical spirit: history-minded but forward-thinking and impossible to pin down. Their sets are adventures built on tension and texture where deep house can melt into dubby techno or EBM grit meets cosmic funk. No gimmicks, just pure dialogue between two storytellers who balance risk with reward. For this set, they will be joined by a selection of friends for even more unpredictable fun.')
