    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Christian AB', 'christian ab', false, 'Over the past decade, Christian AB – who makes his Dekmantel debut this summer – has built a distinctive voice in electronic music through deep, vinyl-based DJing and production. His sets move fluidly between house, techno, breaks and electro – blending his bottomless musical knowledge with an instinctive, razor-sharp understanding of the eb and flow of the dancefloor. As a producer, the Berlin-based artist has released work on imprints such as Faith Beat and Timeless, translating his vision into records that equally stand out for their clarity and depth. We’re thrilled to have him play the forest for the very first time.', 'https://dekmantelfestival.com/artists/christian-ab', 'festival:dekmantel-2026', 'Over the past decade, Christian AB – who makes his Dekmantel debut this summer – has built a distinctive voice in electronic music through deep, vinyl-based DJing and production. His sets move fluidly between house, techno, breaks and electro – blending his bottomless musical knowledge with an instinctive, razor-sharp understanding of the eb and flow of the dancefloor. As a producer, the Berlin-based artist has released work on imprints such as Faith Beat and Timeless, translating his vision into records that equally stand out for their clarity and depth. We’re thrilled to have him play the forest for the very first time.')
