  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Mad Miran & Quest', 'mad miran & quest', false, 'United by a shared love for digging deep into the archives of electronic music are mad miran and Quest. For Dekmantel 2026, the two eclectic selectors team up for a B2B for the very first time. 

Quest is a vinyl devotee on a mission to fuse forgotten gems with future classics. Shaped by underground Italian hip-hop, early UK sounds, and a formative stint in London at Vinyl Pimp, his fluid, instinctive style reflects a lifetime spent honing the craft. Now based in Berlin, he’s earned a reputation as one of the scene’s sharpest selectors and runs La Nota Del Diablo, a label dedicated to eccentric, emotive club music.

Barcelona-based mad miran is among the most exciting talents to emerge from the Dutch club scene. Since her Dekmantel debut in 2022, she’s become a familiar force, known for her “genres are disturbing” ethos. Expect fearless trips through breaks, electro, IDM, and archival rave – played with intelligence, intuition, and unmistakable impact.', 'https://dekmantelfestival.com/artists/mad-miran-quest', 'festival:dekmantel-2026', 'United by a shared love for digging deep into the archives of electronic music are mad miran and Quest. For Dekmantel 2026, the two eclectic selectors team up for a B2B for the very first time. 

Quest is a vinyl devotee on a mission to fuse forgotten gems with future classics. Shaped by underground Italian hip-hop, early UK sounds, and a formative stint in London at Vinyl Pimp, his fluid, instinctive style reflects a lifetime spent honing the craft. Now based in Berlin, he’s earned a reputation as one of the scene’s sharpest selectors and runs La Nota Del Diablo, a label dedicated to eccentric, emotive club music.

Barcelona-based mad miran is among the most exciting talents to emerge from the Dutch club scene. Since her Dekmantel debut in 2022, she’s become a familiar force, known for her “genres are disturbing” ethos. Expect fearless trips through breaks, electro, IDM, and archival rave – played with intelligence, intuition, and unmistakable impact.')
