  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Livwutang', 'livwutang', false, 'Livwutang (Seattle-raised, NYC-based) came up through DIY raves and pirate radio and is now a regular at cult clubs and festivals across the globe. Her sound moves freely between hypnotic dub, Central and West African rhythms and the history of Black American music. All of this comes through in her widescreen sets, her curation of the Eto Ano label and her hosting of its show on The Lot Radio. What makes livwutang stand out among her peers is the confidence of her selections and her ability to shift through moods: from the serene to the deep, the energetic to the melodic – subtly shifting from dubbed-out depths to buoyant club rhythms via tribal techno. There’s an ever-present spirituality that adds an extra layer of intrigue to her sound, which you simply have to experience in the flesh.', 'https://dekmantelfestival.com/artists/livwutang', 'festival:dekmantel-2026', 'Livwutang (Seattle-raised, NYC-based) came up through DIY raves and pirate radio and is now a regular at cult clubs and festivals across the globe. Her sound moves freely between hypnotic dub, Central and West African rhythms and the history of Black American music. All of this comes through in her widescreen sets, her curation of the Eto Ano label and her hosting of its show on The Lot Radio. What makes livwutang stand out among her peers is the confidence of her selections and her ability to shift through moods: from the serene to the deep, the energetic to the melodic – subtly shifting from dubbed-out depths to buoyant club rhythms via tribal techno. There’s an ever-present spirituality that adds an extra layer of intrigue to her sound, which you simply have to experience in the flesh.')
