  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Actress & Carl Craig', 'actress & carl craig', false, 'In a truly historic convergence, Carl Craig – the techno architect whose genre-defining work has shaped club culture for over three decades – meets Actress, the mercurial UK artist celebrated for dissolving boundaries between dance music, abstraction, and emotional immediacy. Craig’s expansive, future-facing vision – rooted in Detroit’s radical musical lineage – collides with Actress’s elusive, avant-garde approach, forged in London’s experimental margins. Together, they span generations, geographies, and philosophies. This is an extraordinarily rare encounter, previously witnessed only once at the DJ-Kicks 30th Anniversary at Drumsheds – a true bucket-list moment to experience two storied careers intertwine in real time.', 'https://dekmantelfestival.com/artists/carl-craig-actress', 'festival:dekmantel-2026', 'In a truly historic convergence, Carl Craig – the techno architect whose genre-defining work has shaped club culture for over three decades – meets Actress, the mercurial UK artist celebrated for dissolving boundaries between dance music, abstraction, and emotional immediacy. Craig’s expansive, future-facing vision – rooted in Detroit’s radical musical lineage – collides with Actress’s elusive, avant-garde approach, forged in London’s experimental margins. Together, they span generations, geographies, and philosophies. This is an extraordinarily rare encounter, previously witnessed only once at the DJ-Kicks 30th Anniversary at Drumsheds – a true bucket-list moment to experience two storied careers intertwine in real time.')
