  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('François K & Suze Ijó', 'françois k & suze ijó', false, 'Born in France and sharpened in New York City, François K’s practice spans disco’s afterlife, house music’s formation, and decades of dancefloor devotion. A pioneer by persistence rather than proclamation, his output encompasses iconic edits released on Prelude Records, alongside generation-defining remixes for major artists including Kraftwerk, U2, and Depeche Mode. Through Body & Soul – the long-running, community-driven dance music institution he co-founded – and his Deep Space residency, François K continues to work the floor as a site of endurance and collective intensity. Joining him for an intergenerational and international B2B is Rotterdam’s Suze Ijó, a selector who carries that same homage to club culture’s legacies forward; raised amid multicultural rhythms, she glides between vinyl and digital formats, crafting sets that journey from Chicago to the Caribbean, delivered with focused intention and warmth.', 'https://dekmantelfestival.com/artists/françois-k-suze-ijó', 'festival:dekmantel-2026', 'Born in France and sharpened in New York City, François K’s practice spans disco’s afterlife, house music’s formation, and decades of dancefloor devotion. A pioneer by persistence rather than proclamation, his output encompasses iconic edits released on Prelude Records, alongside generation-defining remixes for major artists including Kraftwerk, U2, and Depeche Mode. Through Body & Soul – the long-running, community-driven dance music institution he co-founded – and his Deep Space residency, François K continues to work the floor as a site of endurance and collective intensity. Joining him for an intergenerational and international B2B is Rotterdam’s Suze Ijó, a selector who carries that same homage to club culture’s legacies forward; raised amid multicultural rhythms, she glides between vinyl and digital formats, crafting sets that journey from Chicago to the Caribbean, delivered with focused intention and warmth.')
