  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Kuniyuki & Satoshi Tomiie', 'kuniyuki & satoshi tomiie', false, 'Joining forces in the early hours of Dekmantel ’26, please welcome Japanese veterans Kuniyuki Takahashi and Satoshi Tomiie. Although Kuniyuki is often considered one of Japan’s best-kept secrets, operating out of Sapporo since the early ’90s, his productions – ranging from transcendental ambient works to spirited deep house – have inspired DJs across the globe and taken him to the world’s finest clubs. Satoshi Tomiie’s work was first picked up by the legendary Frankie Knuckles in the ’80s, leading him to relocate to New York City. Since then, he has been shaping the worldwide underground through deep, textural house and techno productions, as well as by curating multiple record labels. This summer, they will play live together for the first time.

Please note that this act is part of Dekmantel at Dawn, which is exclusively accessible to weekend ticket holders.', 'https://dekmantelfestival.com/artists/kuniyuki-satoshi-tomiie-live', 'festival:dekmantel-2026', 'Joining forces in the early hours of Dekmantel ’26, please welcome Japanese veterans Kuniyuki Takahashi and Satoshi Tomiie. Although Kuniyuki is often considered one of Japan’s best-kept secrets, operating out of Sapporo since the early ’90s, his productions – ranging from transcendental ambient works to spirited deep house – have inspired DJs across the globe and taken him to the world’s finest clubs. Satoshi Tomiie’s work was first picked up by the legendary Frankie Knuckles in the ’80s, leading him to relocate to New York City. Since then, he has been shaping the worldwide underground through deep, textural house and techno productions, as well as by curating multiple record labels. This summer, they will play live together for the first time.

Please note that this act is part of Dekmantel at Dawn, which is exclusively accessible to weekend ticket holders.')
