  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Niks', 'niks', false, 'NTS, Rinse FM, and BBC Radio regular NIKS has left a significant mark on current club culture, extending far beyond her work as a DJ and producer. She co-founded the Black Artist Database, a crowd-sourced resource of Black-owned labels, artists, and producers designed to amplify and uplift talent – now expanded into its own label and event series. Her house-focused sets draw from 90s breaks and groovy techno, and in true Londoner fashion: she always leaves space for warm bass and dub influences.', 'https://dekmantelfestival.com/artists/niks-2', 'festival:dekmantel-2026', 'NTS, Rinse FM, and BBC Radio regular NIKS has left a significant mark on current club culture, extending far beyond her work as a DJ and producer. She co-founded the Black Artist Database, a crowd-sourced resource of Black-owned labels, artists, and producers designed to amplify and uplift talent – now expanded into its own label and event series. Her house-focused sets draw from 90s breaks and groovy techno, and in true Londoner fashion: she always leaves space for warm bass and dub influences.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Gabrielle Kwarteng', 'gabrielle kwarteng', false, 'Championing the house grooves of New York, where she was born and raised, the now Berlin-based Gabrielle Kwarteng knows like no other how to keep dancers locked in. During her regular radio appearances on NYC’s The Lot, Berlin’s Refuge, or London’s NTS, she showcases her far reaching music taste. Kwarteng weaves together different decades of electronic music with impressive ease: from the freshest techno cuts, to funk and early house, but always honouring the Black roots of dance music. As she has shown during her many previous Dekmantel, Lentekabinet, or Dekmantel Selectors sets, there’s no escaping from the infectious energy when Kwarteng is in charge of the dancefloor.', 'https://dekmantelfestival.com/artists/gabrielle-kwarteng', 'festival:dekmantel-2026', 'Championing the house grooves of New York, where she was born and raised, the now Berlin-based Gabrielle Kwarteng knows like no other how to keep dancers locked in. During her regular radio appearances on NYC’s The Lot, Berlin’s Refuge, or London’s NTS, she showcases her far reaching music taste. Kwarteng weaves together different decades of electronic music with impressive ease: from the freshest techno cuts, to funk and early house, but always honouring the Black roots of dance music. As she has shown during her many previous Dekmantel, Lentekabinet, or Dekmantel Selectors sets, there’s no escaping from the infectious energy when Kwarteng is in charge of the dancefloor.')
