  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Blasha & Allatt', 'blasha & allatt', false, 'In Manchester, the Northern English city steeped in musical history, Blasha & Allatt established the legendary Meat Free—a party series hailed as one of the wildest techno raves in the UK. This far-reaching legacy propelled them into the Dutch scene, where they quickly became residents at Vault Sessions and contributed to the positivesource label alongside like-minded enthusiasts of wormholing bangers, such as Phil Berg, Spekki Webu, and Ipeo. Behind the decks, the pair have a symbiotic energy, mixing through an expansive repertoire of techno, house, and on-point four-to-the-floor. Returning for the second year in a row, Blasha & Allatt are set to absolutely bring it once again.', 'https://dekmantelfestival.com/artists/blasha-allatt-2', 'festival:dekmantel-2026', 'In Manchester, the Northern English city steeped in musical history, Blasha & Allatt established the legendary Meat Free—a party series hailed as one of the wildest techno raves in the UK. This far-reaching legacy propelled them into the Dutch scene, where they quickly became residents at Vault Sessions and contributed to the positivesource label alongside like-minded enthusiasts of wormholing bangers, such as Phil Berg, Spekki Webu, and Ipeo. Behind the decks, the pair have a symbiotic energy, mixing through an expansive repertoire of techno, house, and on-point four-to-the-floor. Returning for the second year in a row, Blasha & Allatt are set to absolutely bring it once again.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Bitter Babe', 'bitter babe', false, 'Artist Profiles - Dekmantel Festival NEWBitter Babe is part of a new generation of artists reshaping the electronic sound of the Latin American diaspora. Originally from Bogotá, emerging through Miami’s thriving underground, and now based in Paris, the genre-defying DJ and producer delivers an energetic blend of bold influences. Moving fluidly between raptor house, breakbeat, techno, guaracha, and infectious dembow, her sound is rooted in bass-heavy grooves and percussive rhythms built for the dancefloor.', 'https://dekmantelfestival.com/artists/bitter-babe', 'festival:dekmantel-2026', 'Artist Profiles - Dekmantel Festival NEWBitter Babe is part of a new generation of artists reshaping the electronic sound of the Latin American diaspora. Originally from Bogotá, emerging through Miami’s thriving underground, and now based in Paris, the genre-defying DJ and producer delivers an energetic blend of bold influences. Moving fluidly between raptor house, breakbeat, techno, guaracha, and infectious dembow, her sound is rooted in bass-heavy grooves and percussive rhythms built for the dancefloor.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Objekt', 'objekt', false, 'A true thing of beauty, Objekt’s DJ sets demand to be experienced in their full splendour – from start to finish; from tears to ecstasy and back again. The Berlin-based DJ and producer has built a reputation for mixes that twist and turn through the outer edges of dance music, pulling together everything from razor-edged techno and industrial rhythms to IDM oddities, ambient experiments, and plenty of bass-heavy wobble. What holds it all together is a meticulous sense of structure: sounds are placed with precision, tension slowly accumulates, and moments of release arrive exactly when they should. Since his initial breakthrough, Objekt has continued to refine this restless approach. In recent years, he launched the label Kapsela, a platform for his evolving sonic experiments and for kindred artists such as PVA and gyrofield, while continuing to reshape expectations of what a club set can be.', 'https://dekmantelfestival.com/artists/objekt', 'festival:dekmantel-2026', 'A true thing of beauty, Objekt’s DJ sets demand to be experienced in their full splendour – from start to finish; from tears to ecstasy and back again. The Berlin-based DJ and producer has built a reputation for mixes that twist and turn through the outer edges of dance music, pulling together everything from razor-edged techno and industrial rhythms to IDM oddities, ambient experiments, and plenty of bass-heavy wobble. What holds it all together is a meticulous sense of structure: sounds are placed with precision, tension slowly accumulates, and moments of release arrive exactly when they should. Since his initial breakthrough, Objekt has continued to refine this restless approach. In recent years, he launched the label Kapsela, a platform for his evolving sonic experiments and for kindred artists such as PVA and gyrofield, while continuing to reshape expectations of what a club set can be.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
