  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Fafi Abdel Nour & Jennifer Loveless', 'fafi abdel nour & jennifer loveless', false, 'Grounded in groove and pleasure, Fafi Abdel Nour and Jennifer Loveless collide. Born to a Syrian family and now based in Amsterdam, Fafi’s practice is shaped by navigating between cultures and identities; his sets draw on melodic tension, elastic rhythm, and the physical charge of disco-adjacent house, informed by years of organising queer club nights in Groningen. Loveless, whose path runs from Toronto’s bass-driven underground to Melbourne’s club circuit, has become known for high-impact, body-forward sets that thrive on queer floors and late-night intensity, moving fluidly across house and techno’s rougher edges. Together, they favour momentum and release, burning bright with ecstatic energy – guided by a simple mantra: love is the message, music is the medium.', 'https://dekmantelfestival.com/artists/fafi-abdel-nour-jennifer-loveless', 'festival:dekmantel-2026', 'Grounded in groove and pleasure, Fafi Abdel Nour and Jennifer Loveless collide. Born to a Syrian family and now based in Amsterdam, Fafi’s practice is shaped by navigating between cultures and identities; his sets draw on melodic tension, elastic rhythm, and the physical charge of disco-adjacent house, informed by years of organising queer club nights in Groningen. Loveless, whose path runs from Toronto’s bass-driven underground to Melbourne’s club circuit, has become known for high-impact, body-forward sets that thrive on queer floors and late-night intensity, moving fluidly across house and techno’s rougher edges. Together, they favour momentum and release, burning bright with ecstatic energy – guided by a simple mantra: love is the message, music is the medium.')
