  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Eris Drew & Octo Octa', 'eris drew & octo octa', false, 'Yes, they’re back! Partners in electronic music, rave culture, spirituality, and – last but not least – romance, Octo Octa and Eris Drew have become something of an underground sensation. Together, these unapologetically trans artists run T4T LUV NRG, a label releasing “alchemical objects for use in DJing, dancing, kissing, and crying.” Based in New Hampshire, USA, their radiant sound spans house, techno, and breakbeat, with a special emphasis on rare vinyl finds and old-school rave gems that bridge the material and non-material realms. Both world-class DJs and producers individually, the B2B chemistry between them is truly out of this world.', 'https://dekmantelfestival.com/artists/octo-octa-eris-drew', 'festival:dekmantel-2026', 'Yes, they’re back! Partners in electronic music, rave culture, spirituality, and – last but not least – romance, Octo Octa and Eris Drew have become something of an underground sensation. Together, these unapologetically trans artists run T4T LUV NRG, a label releasing “alchemical objects for use in DJing, dancing, kissing, and crying.” Based in New Hampshire, USA, their radiant sound spans house, techno, and breakbeat, with a special emphasis on rare vinyl finds and old-school rave gems that bridge the material and non-material realms. Both world-class DJs and producers individually, the B2B chemistry between them is truly out of this world.')
