  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Dimi Angélis', 'dimi angélis', false, 'If you have any connection to Amsterdam’s electronic scene, the name Dimi Angélis – aka Dimitri van Duynhoven – is sure to ring a bell. Ever since finding his footing at illegal raves and warehouse parties in the ’90s, the Dutch artist has fulfilled many roles: from organiser and promoter to globally recognised DJ, producer and label head. The common thread running through all of these functions is the artist’s love for hammering techno that always tells an uncompromising story. Strongly opposed to a phenomenon he calls “easy pleasing,” a Dimi Angélis set always contains a sense of sonic familiarity, only to then throw you off while wrapping you around his finger. If you still need an introduction to the Dimi direction, the solo label ANGLS – on which he’s been releasing techno productions in all possible shades for over a decade – is the perfect place to start.', 'https://dekmantelfestival.com/artists/dim-angélis', 'festival:dekmantel-2026', 'If you have any connection to Amsterdam’s electronic scene, the name Dimi Angélis – aka Dimitri van Duynhoven – is sure to ring a bell. Ever since finding his footing at illegal raves and warehouse parties in the ’90s, the Dutch artist has fulfilled many roles: from organiser and promoter to globally recognised DJ, producer and label head. The common thread running through all of these functions is the artist’s love for hammering techno that always tells an uncompromising story. Strongly opposed to a phenomenon he calls “easy pleasing,” a Dimi Angélis set always contains a sense of sonic familiarity, only to then throw you off while wrapping you around his finger. If you still need an introduction to the Dimi direction, the solo label ANGLS – on which he’s been releasing techno productions in all possible shades for over a decade – is the perfect place to start.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('GiGi FM', 'gigi fm', false, 'GiGi FM is a multidisciplinary artist, DJ, producer, and professionally trained dancer whose practice is rooted in movement, astrology, philosophy, and cosmological thought. Beginning her journey in the underground squat-rave scene of South London and now based in Berlin, she has developed a distinctive approach that balances physical intensity with emotional depth. An NTS Radio resident for almost a decade, her mixes move fluidly between techno, bass, breaks, and ambient soundscapes, creating immersive experiences and states of collective ecstasy.', 'https://dekmantelfestival.com/artists/gigi-fm', 'festival:dekmantel-2026', 'GiGi FM is a multidisciplinary artist, DJ, producer, and professionally trained dancer whose practice is rooted in movement, astrology, philosophy, and cosmological thought. Beginning her journey in the underground squat-rave scene of South London and now based in Berlin, she has developed a distinctive approach that balances physical intensity with emotional depth. An NTS Radio resident for almost a decade, her mixes move fluidly between techno, bass, breaks, and ambient soundscapes, creating immersive experiences and states of collective ecstasy.')
  ON CONFLICT (sort_name) DO UPDATE SET
