    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('GiGi FM & JakoJako', 'gigi fm & jakojako', false, 'An expert modular synthesist and Berghain resident, JakoJako is known for long-form, hypnotic techno shaped by precision, depth, and emotional weight, across albums including Metamorphose (2022) and Tết 41 (2025). GiGi FM is a DJ, producer, and multidisciplinary artist whose work is informed by professional dance training and a long-running residency on NTS Radio, where she has developed an expansive, physical approach to club music spanning bass, house, and ambient forms. Closely matched in their attention to timing and intensity, their B2B set unfolds as a focused exchange between two artists equally devoted to their craft and to the shared experience of the dancefloor.', 'https://dekmantelfestival.com/artists/jakojako-gigi-fm', 'festival:dekmantel-2026', 'An expert modular synthesist and Berghain resident, JakoJako is known for long-form, hypnotic techno shaped by precision, depth, and emotional weight, across albums including Metamorphose (2022) and Tết 41 (2025). GiGi FM is a DJ, producer, and multidisciplinary artist whose work is informed by professional dance training and a long-running residency on NTS Radio, where she has developed an expansive, physical approach to club music spanning bass, house, and ambient forms. Closely matched in their attention to timing and intensity, their B2B set unfolds as a focused exchange between two artists equally devoted to their craft and to the shared experience of the dancefloor.')
