    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Steffi', 'steffi', false, 'Decades into her career, Steffi remains as curious and quietly unpredictable as ever. She has been DJing almost continuously since the mid-1990s – first in her hometown of Eindhoven, then Amsterdam, and from 2007 onward in Berlin, where she became a Panorama Bar resident. More recently, in 2020, she relocated with longtime collaborator Virginia to the idyllic Portuguese countryside, a retreat that has seemingly only sharpened her club-forward sensibility. Her recent output, including the much-lauded album Patterns Of Vibration, leans into moments of collective euphoria and dancefloor debauchery. As a DJ, Steffi channels these qualities through groove-led sets that move fluidly between house, techno, and electro-rooted forms, drawing on electronic history while remaining firmly present tense.', 'https://dekmantelfestival.com/artists/steffi', 'festival:dekmantel-2026', 'Decades into her career, Steffi remains as curious and quietly unpredictable as ever. She has been DJing almost continuously since the mid-1990s – first in her hometown of Eindhoven, then Amsterdam, and from 2007 onward in Berlin, where she became a Panorama Bar resident. More recently, in 2020, she relocated with longtime collaborator Virginia to the idyllic Portuguese countryside, a retreat that has seemingly only sharpened her club-forward sensibility. Her recent output, including the much-lauded album Patterns Of Vibration, leans into moments of collective euphoria and dancefloor debauchery. As a DJ, Steffi channels these qualities through groove-led sets that move fluidly between house, techno, and electro-rooted forms, drawing on electronic history while remaining firmly present tense.')
