  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Luke Slater', 'luke slater', false, 'When techno crossed the Atlantic and made its way to the UK, it was embraced and expanded by a handful of key artists. Among the most significant was Luke Slater, a chameleonic figure who has spent more than three decades moving through the genre''s many forms, forging a body of work that remains as influential as it is difficult to categorise. Across projects including Planetary Assault Systems, The 7th Plain and L.B. Dub Corp, Slater has continually reinvented his approach, traversing driving techno, deep house, dub and experimental electronics. A longtime resident at Berghain and famously the first non-German artist to release on Ostgut Ton, he occupies a singular position within electronic music: equally revered as innovator, craftsman and selector.', 'https://dekmantelfestival.com/artists/luke-slater', 'festival:dekmantel-2026', 'When techno crossed the Atlantic and made its way to the UK, it was embraced and expanded by a handful of key artists. Among the most significant was Luke Slater, a chameleonic figure who has spent more than three decades moving through the genre''s many forms, forging a body of work that remains as influential as it is difficult to categorise. Across projects including Planetary Assault Systems, The 7th Plain and L.B. Dub Corp, Slater has continually reinvented his approach, traversing driving techno, deep house, dub and experimental electronics. A longtime resident at Berghain and famously the first non-German artist to release on Ostgut Ton, he occupies a singular position within electronic music: equally revered as innovator, craftsman and selector.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

