    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Oscar Mulero', 'oscar mulero', false, 'Earlier in the festival, catch Oscar Mulero appearing B2B with Dasha Rush, here, he takes the reins solo, unleashing his unique strain of techno: hard-edged, deeply hypnotic, and honed over more than three decades. A foundational figure in Spain’s underground since the 1990s, he was instrumental in shaping Madrid’s scene through the legendary The Omen, one of the city’s most influential early techno clubs. Through his labels Warm Up and PoleGroup Recordings, as well as a consistently uncompromising body of productions and DJ sets, he has become synonymous with a sound that continues to define and expand the genre’s meditative core while influencing generations of artists around the globe.', 'https://dekmantelfestival.com/artists/oscar-mulero-2', 'festival:dekmantel-2026', 'Earlier in the festival, catch Oscar Mulero appearing B2B with Dasha Rush, here, he takes the reins solo, unleashing his unique strain of techno: hard-edged, deeply hypnotic, and honed over more than three decades. A foundational figure in Spain’s underground since the 1990s, he was instrumental in shaping Madrid’s scene through the legendary The Omen, one of the city’s most influential early techno clubs. Through his labels Warm Up and PoleGroup Recordings, as well as a consistently uncompromising body of productions and DJ sets, he has become synonymous with a sound that continues to define and expand the genre’s meditative core while influencing generations of artists around the globe.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Dasha Rush & Oscar Mulero', 'dasha rush & oscar mulero', false, 'A meeting of two masters at the peak of their powers, Oscar Mulero and Dasha Rush are techno titans. A foundational figure in Spain’s underground since the early 1990s, Mulero was instrumental in shaping Madrid’s scene through the legendary The Omen, one of the city’s most influential early techno institutions, and continues to define the genre’s hard-edged, meditative core via his labels Warm Up and PoleGroup Recordings. Rush, meanwhile, refuses convention at every turn, articulating a shadowy, evocative synthesis of club culture and experimentalism via releases on her Fullpanda imprint and immersive, spatially driven performances. Together, they share an interest in sound as material – looped, sculpted, and charged – building long arcs of pressure that reward deep attention as much as physical surrender.', 'https://dekmantelfestival.com/artists/dasha-rush-oscar-mulero', 'festival:dekmantel-2026', 'A meeting of two masters at the peak of their powers, Oscar Mulero and Dasha Rush are techno titans. A foundational figure in Spain’s underground since the early 1990s, Mulero was instrumental in shaping Madrid’s scene through the legendary The Omen, one of the city’s most influential early techno institutions, and continues to define the genre’s hard-edged, meditative core via his labels Warm Up and PoleGroup Recordings. Rush, meanwhile, refuses convention at every turn, articulating a shadowy, evocative synthesis of club culture and experimentalism via releases on her Fullpanda imprint and immersive, spatially driven performances. Together, they share an interest in sound as material – looped, sculpted, and charged – building long arcs of pressure that reward deep attention as much as physical surrender.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Loradeniz', 'loradeniz', false, 'DJ, pianist, producer, vocalist, and composer, Loradeniz is a kaleidoscopic tour-de-force. The multidisciplinary project conceived by Istanbul-born, Amsterdam-based artist Deniz Omeroglu has quietly grown into a cult name, particularly known for hypnotic and deeply sensitive, voice-led records released on labels such as Music From Memory, Nous’klaer Audio, and Artificial Dance. Drawing on a wide-ranging musical background rooted in classical training and experimental sound design, she channels this breadth into immersive mixes that drift between deep house, bass, psychedelic techno, trance, ambient, and acid. With Loradeniz, the dancefloor deepens into a shifting, oceanic terrain – contours merging, dissolving, and reforming, shaped as much by atmosphere as by rhythm.', 'https://dekmantelfestival.com/artists/loradeniz', 'festival:dekmantel-2026', 'DJ, pianist, producer, vocalist, and composer, Loradeniz is a kaleidoscopic tour-de-force. The multidisciplinary project conceived by Istanbul-born, Amsterdam-based artist Deniz Omeroglu has quietly grown into a cult name, particularly known for hypnotic and deeply sensitive, voice-led records released on labels such as Music From Memory, Nous’klaer Audio, and Artificial Dance. Drawing on a wide-ranging musical background rooted in classical training and experimental sound design, she channels this breadth into immersive mixes that drift between deep house, bass, psychedelic techno, trance, ambient, and acid. With Loradeniz, the dancefloor deepens into a shifting, oceanic terrain – contours merging, dissolving, and reforming, shaped as much by atmosphere as by rhythm.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
