  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Brodinski & Slikback', 'brodinski & slikback', false, 'This is where dancefloor maximalism comes alive – fast, furious, and full of fervour. Kenyan producer and DJ Slikback is among the most uncompromising voices in contemporary club music, known for a raw, percussive sound built brick by brick in Fruity Loops, merging elements of techno, gqom, and tearout dubstep, released on labels such as Nyege Nyege Tapes and Planet Mu. Teaming up with him is Paris-born, LA-based Brodinski, who made his mark in the 2010s through his Bromance label – a veritable laboratory for hybrid sounds. After several studio collaborations, the pair unite behind the decks for a back-to-back, one that promises relentless momentum from start to finish.', 'https://dekmantelfestival.com/artists/brodinski-slikback', 'festival:dekmantel-2026', 'This is where dancefloor maximalism comes alive – fast, furious, and full of fervour. Kenyan producer and DJ Slikback is among the most uncompromising voices in contemporary club music, known for a raw, percussive sound built brick by brick in Fruity Loops, merging elements of techno, gqom, and tearout dubstep, released on labels such as Nyege Nyege Tapes and Planet Mu. Teaming up with him is Paris-born, LA-based Brodinski, who made his mark in the 2010s through his Bromance label – a veritable laboratory for hybrid sounds. After several studio collaborations, the pair unite behind the decks for a back-to-back, one that promises relentless momentum from start to finish.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
