  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Jasss', 'jasss', false, 'Following her daytime b2b with Vlada, JASSS returns to Dekmantel by night for a solo set, offering a deeper dive into her singular artistic vision. For over a decade, the Spanish-born, Berlin-based artist has pushed at the boundaries of leftfield dance, approaching sound as a material to be stretched, fractured, and reassembled in real time. Her productions — released on labels such as iDEAL Recordings and Whities — are defined by dense percussion and disorientating, intoxicating textures, drawing together seemingly opposing forces: precision and chaos, sensuality and abrasion, physicality and atmosphere. As a DJ, she channels this same explosive energy, colliding contemporary club and experimental electronics with striking dexterity and instinct.', 'https://dekmantelfestival.com/artists/jasss', 'festival:dekmantel-2026', 'Following her daytime b2b with Vlada, JASSS returns to Dekmantel by night for a solo set, offering a deeper dive into her singular artistic vision. For over a decade, the Spanish-born, Berlin-based artist has pushed at the boundaries of leftfield dance, approaching sound as a material to be stretched, fractured, and reassembled in real time. Her productions — released on labels such as iDEAL Recordings and Whities — are defined by dense percussion and disorientating, intoxicating textures, drawing together seemingly opposing forces: precision and chaos, sensuality and abrasion, physicality and atmosphere. As a DJ, she channels this same explosive energy, colliding contemporary club and experimental electronics with striking dexterity and instinct.')
