  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Jasss & Vlada', 'jasss & vlada', false, 'Two of the most finessed DJs in the game right now, JASSS and Vlada go B2B at Dekmantel Festival ’26. On the one hand, there’s JASSS’s high-intensity, razor-sharp juggling of electronic rarities – from post-club ambient, industrial and baroque pop to fast, raw, relentless techno (she is both a conceptual sound artist and a long-time Herrensauna resident). On the other, there’s Vlada, whose dark and shimmering blend of house, techno and trance – and all things in-between – is mischievous and seductive, punctuated by perfectly timed bursts of dancefloor delirium. When these artists meet in the booth, the only sure thing is that you’ll need to hold on tight for a top-tier quality, deeply musical trip.', 'https://dekmantelfestival.com/artists/jasss-vlada', 'festival:dekmantel-2026', 'Two of the most finessed DJs in the game right now, JASSS and Vlada go B2B at Dekmantel Festival ’26. On the one hand, there’s JASSS’s high-intensity, razor-sharp juggling of electronic rarities – from post-club ambient, industrial and baroque pop to fast, raw, relentless techno (she is both a conceptual sound artist and a long-time Herrensauna resident). On the other, there’s Vlada, whose dark and shimmering blend of house, techno and trance – and all things in-between – is mischievous and seductive, punctuated by perfectly timed bursts of dancefloor delirium. When these artists meet in the booth, the only sure thing is that you’ll need to hold on tight for a top-tier quality, deeply musical trip.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('AYA', 'aya', false, 'Aya’s work explores the transformative impact of sound, memory and experience on the physical body. Moving between fractured club music, experimental electronics and high-pressure rhythms, both her productions and performances channel raw emotion – “I like crying in the booth” – and release. Known for raw sets that push both structure and sensation, aya draws heavily on the restless energy of the think break (aka the second most sampled drum break in music history after the Amen) while blurring the boundaries between the dancefloor and more abstract listening spaces. Since emerging under her own name, she has released on labels including Tri Angle Records, Astral Plane and Wisdom Teeth. This summer marks the artist’s Dekmantel debut.', 'https://dekmantelfestival.com/artists/aya-live', 'festival:dekmantel-2026', 'Aya’s work explores the transformative impact of sound, memory and experience on the physical body. Moving between fractured club music, experimental electronics and high-pressure rhythms, both her productions and performances channel raw emotion – “I like crying in the booth” – and release. Known for raw sets that push both structure and sensation, aya draws heavily on the restless energy of the think break (aka the second most sampled drum break in music history after the Amen) while blurring the boundaries between the dancefloor and more abstract listening spaces. Since emerging under her own name, she has released on labels including Tri Angle Records, Astral Plane and Wisdom Teeth. This summer marks the artist’s Dekmantel debut.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Cheyanne Hudson', 'cheyanne hudson', false, 'Cheyanne Hudson is an undeniably bright new star on the club firmament. Born and raised in the Netherlands, the British Jamaican/Hong Kong DJ is a resident on Brussels’ Kiosk Radio whose sound is just as fluently diverse as her background. Sound system culture, in particular, is where Cheyanne draws her inspiration, with her sets thriving on snappy amen breaks, low-end frequencies and dubby chants. And while her energy in the booth is light and breezy – yes, go see and feel it for yourself – the deep, dark and gloomy sounds she dabbles in are strong enough to seize both mind and body.', 'https://dekmantelfestival.com/artists/cheyanne-hudson', 'festival:dekmantel-2026', 'Cheyanne Hudson is an undeniably bright new star on the club firmament. Born and raised in the Netherlands, the British Jamaican/Hong Kong DJ is a resident on Brussels’ Kiosk Radio whose sound is just as fluently diverse as her background. Sound system culture, in particular, is where Cheyanne draws her inspiration, with her sets thriving on snappy amen breaks, low-end frequencies and dubby chants. And while her energy in the booth is light and breezy – yes, go see and feel it for yourself – the deep, dark and gloomy sounds she dabbles in are strong enough to seize both mind and body.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Ikonika', 'ikonika', false, 'Emerging out of the late-2000s dubstep vanguard – one of the few non-male acts visible within the scene at the time – and the UK funky underground, Ikonika cut against bass music’s darker orthodoxies with colour, swing, and emotional depth. With releases on Night Slugs, Planet Mu, and Don’t Be Afraid (DBA), they have long been affiliated with the influential Hyperdub label, which released their debut album Contact, Love, Want, Have (2010) – a pioneering record blending elements of garage, synth-pop, and R&B with bright melodies and retro-futurist textures. Decades on from their breakout, Ikonika shows no signs of slowing down, continuing to put out singular productions and deliver highly dynamic DJ sets that reassemble UK club languages into a powerfully fresh vernacular – mischievous, melodic, and unmistakably London.', 'https://dekmantelfestival.com/artists/ikonika', 'festival:dekmantel-2026', 'Emerging out of the late-2000s dubstep vanguard – one of the few non-male acts visible within the scene at the time – and the UK funky underground, Ikonika cut against bass music’s darker orthodoxies with colour, swing, and emotional depth. With releases on Night Slugs, Planet Mu, and Don’t Be Afraid (DBA), they have long been affiliated with the influential Hyperdub label, which released their debut album Contact, Love, Want, Have (2010) – a pioneering record blending elements of garage, synth-pop, and R&B with bright melodies and retro-futurist textures. Decades on from their breakout, Ikonika shows no signs of slowing down, continuing to put out singular productions and deliver highly dynamic DJ sets that reassemble UK club languages into a powerfully fresh vernacular – mischievous, melodic, and unmistakably London.')
