  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Scratchclart & State OFFF', 'scratchclart & state offf', false, 'Scratchclart (aka Scratcha DVA) is a London-born DJ, producer and sound designer whose decades-long journey from pirate radio to Hyperdub releases has made him an unmissable voice in UK club culture. Always evolving, his sets weave grime, gqom, UK funky, amapiano and global club threads into future-forward soundscapes. At our ’26 edition, Scratch goes back-to-back with State OFFF – the Zimbabwe-born, Amsterdam-based artist who thrives in the “cracks between scenes” and who opened The Nest last year. State OFFF’s sound is equally shaped by Durban gqom, São Paulo funk, Baltimore club and London basslines – but welded into something deeper and heavier. Buckle up for restless rhythms and low-end genre-bending.', 'https://dekmantelfestival.com/artists/scratchclart-state-offf', 'festival:dekmantel-2026', 'Scratchclart (aka Scratcha DVA) is a London-born DJ, producer and sound designer whose decades-long journey from pirate radio to Hyperdub releases has made him an unmissable voice in UK club culture. Always evolving, his sets weave grime, gqom, UK funky, amapiano and global club threads into future-forward soundscapes. At our ’26 edition, Scratch goes back-to-back with State OFFF – the Zimbabwe-born, Amsterdam-based artist who thrives in the “cracks between scenes” and who opened The Nest last year. State OFFF’s sound is equally shaped by Durban gqom, São Paulo funk, Baltimore club and London basslines – but welded into something deeper and heavier. Buckle up for restless rhythms and low-end genre-bending.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Batu', 'batu', false, 'We just can’t seem to get enough of Batu – and there’s a reason he keeps coming back to Dekmantel. A near-permanent fixture at the festival over the years, the Timedance founder has built a reputation for sets that never repeat themselves, constantly reworking his sound while staying tightly locked to the dancefloor. Rooted in UK bass but restless by nature, Batu’s approach favours intricate polyrhythms and elastic low-end pressure that feels perpetually in motion. From his 2022 debut album Opal to a steady run of forward-leaning releases on Timedance and beyond, his music resists fixed form, thriving instead on tension, detail and surprise. Familiar, yes – but never predictable.', 'https://dekmantelfestival.com/artists/batu-2', 'festival:dekmantel-2026', 'We just can’t seem to get enough of Batu – and there’s a reason he keeps coming back to Dekmantel. A near-permanent fixture at the festival over the years, the Timedance founder has built a reputation for sets that never repeat themselves, constantly reworking his sound while staying tightly locked to the dancefloor. Rooted in UK bass but restless by nature, Batu’s approach favours intricate polyrhythms and elastic low-end pressure that feels perpetually in motion. From his 2022 debut album Opal to a steady run of forward-leaning releases on Timedance and beyond, his music resists fixed form, thriving instead on tension, detail and surprise. Familiar, yes – but never predictable.')
