  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Novelist & Dj Slimzee', 'novelist & dj slimzee', false, 'Grime-heads step up for a Dekmantel debut that’s sure to be the stuff of legend: godfather of the scene Slimzee links with Novelist, of Square – the South London crew that helped rewire the sound in the mid-2010s with a sharper, more exploratory edge. Slimzee’s influence runs deep: as a founding force on Rinse FM, the station that gave early bass-heavy UK styles a home, his radio sets and records shaped the music’s character long before it had a name. Emerging a generation later, Novelist extends that lineage with surgical precision and political clarity, cutting through beats with control and power. His 2025 album Audacity – an eight-track, self-produced statement – threads old-school grit through a future-facing lens. In tandem, they lock into pure propulsion: pressure applied, discipline intact, vision locked forward.', 'https://dekmantelfestival.com/artists/dj-slimzee-novelist-live', 'festival:dekmantel-2026', 'Grime-heads step up for a Dekmantel debut that’s sure to be the stuff of legend: godfather of the scene Slimzee links with Novelist, of Square – the South London crew that helped rewire the sound in the mid-2010s with a sharper, more exploratory edge. Slimzee’s influence runs deep: as a founding force on Rinse FM, the station that gave early bass-heavy UK styles a home, his radio sets and records shaped the music’s character long before it had a name. Emerging a generation later, Novelist extends that lineage with surgical precision and political clarity, cutting through beats with control and power. His 2025 album Audacity – an eight-track, self-produced statement – threads old-school grit through a future-facing lens. In tandem, they lock into pure propulsion: pressure applied, discipline intact, vision locked forward.')
