  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Shy FX & Tasha', 'shy fx & tasha', false, 'Following a standout B2B at Open Ground, where an instant connection made a repeat inevitable, Shy FX joins forces with Tasha. A true architect of UK bass culture, Shy FX emerged from London’s early 1990s sound system scene and is best known for defining records such as Original Nuttah, shaping the DNA of jungle through razor-sharp breakbeats, low-end pressure, and enduring dancefloor clarity. From a new generation of British selectors, Tasha (founder of the Neighbourhood label and party series), rose to prominence in the late 2010s as a deeply grassroots figure, rigorously invested in UK-rooted club music, with sets that move fluidly between techno, dubstep, breaks, and beyond. Together, this B2B brings foundational legacy into live conversation with the future.', 'https://dekmantelfestival.com/artists/shy-fx-tasha', 'festival:dekmantel-2026', 'Following a standout B2B at Open Ground, where an instant connection made a repeat inevitable, Shy FX joins forces with Tasha. A true architect of UK bass culture, Shy FX emerged from London’s early 1990s sound system scene and is best known for defining records such as Original Nuttah, shaping the DNA of jungle through razor-sharp breakbeats, low-end pressure, and enduring dancefloor clarity. From a new generation of British selectors, Tasha (founder of the Neighbourhood label and party series), rose to prominence in the late 2010s as a deeply grassroots figure, rigorously invested in UK-rooted club music, with sets that move fluidly between techno, dubstep, breaks, and beyond. Together, this B2B brings foundational legacy into live conversation with the future.')
