  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('PLO Man & Skee Mask', 'plo man & skee mask', false, 'Here at Dekmantel 2026, PLO Man and Skee Mask are about to make history. Two juggernaut figures who have never before shared the decks, this long-awaited B2B brings together distinct but kindred sensibilities. PLO Man has developed an international cult following for playing freaked-out sounds on wax, earning a reputation as a fearless selector with an ear for the strange and the sublime. A representative of the label ACTING PRESS, his work spans solo and collaborative projects that blur club function and sonic exploration. Meanwhile, Germany’s Bryan Müller – aka Skee Mask – is a key figure within the Ilian Tape universe, combining techno, breakbeat, jungle, and ambient, as echoes of 1990s hardcore collide with something new and unmistakably his own. Expect risk, range, and a moment that''s been years in the making.', 'https://dekmantelfestival.com/artists/plo-man-skee-mask', 'festival:dekmantel-2026', 'Here at Dekmantel 2026, PLO Man and Skee Mask are about to make history. Two juggernaut figures who have never before shared the decks, this long-awaited B2B brings together distinct but kindred sensibilities. PLO Man has developed an international cult following for playing freaked-out sounds on wax, earning a reputation as a fearless selector with an ear for the strange and the sublime. A representative of the label ACTING PRESS, his work spans solo and collaborative projects that blur club function and sonic exploration. Meanwhile, Germany’s Bryan Müller – aka Skee Mask – is a key figure within the Ilian Tape universe, combining techno, breakbeat, jungle, and ambient, as echoes of 1990s hardcore collide with something new and unmistakably his own. Expect risk, range, and a moment that''s been years in the making.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Nicolas Lutz', 'nicolas lutz', false, 'Nicolas Lutz, originally from Montevideo, Uruguay, operates firmly at the outer limits of dancefloor culture. A cult selector with an instinct for the margins, he’s known for testing the unfamiliar in real time – unearthing strange, overlooked records and letting them slowly reveal their power. His sets slip through shadowy zones and sudden left turns, guided by feel rather than fashion. Precision without rigidity, curiosity without compromise, Lutz brings the same philosophy to his My Own Jupiter label, where patience, depth and discovery remain the guiding principles. As a DJ, he favours off-grid house and techno, broken electro, and cosmic oddities – expect extended arcs and carefully calibrated tension; his authority lies not in spectacle, but in unfaltering intuition.', 'https://dekmantelfestival.com/artists/nicolas-lutz', 'festival:dekmantel-2026', 'Nicolas Lutz, originally from Montevideo, Uruguay, operates firmly at the outer limits of dancefloor culture. A cult selector with an instinct for the margins, he’s known for testing the unfamiliar in real time – unearthing strange, overlooked records and letting them slowly reveal their power. His sets slip through shadowy zones and sudden left turns, guided by feel rather than fashion. Precision without rigidity, curiosity without compromise, Lutz brings the same philosophy to his My Own Jupiter label, where patience, depth and discovery remain the guiding principles. As a DJ, he favours off-grid house and techno, broken electro, and cosmic oddities – expect extended arcs and carefully calibrated tension; his authority lies not in spectacle, but in unfaltering intuition.')
  ON CONFLICT (sort_name) DO UPDATE SET
