    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Channel One', 'channel one', false, 'Bass for breakfast? Yes, please! Last with us in ’22, we’re thrilled to have Channel One back in the forest – this time for a special morning session as part of our At Dawn programme. One of the UK’s most beloved and respected reggae sound systems, Channel One is comprised of DJ Mikey Dread, MC Macky Banton and MC Ras Sherby. Formed in the late seventies, they first played London’s Notting Hill Carnival in 1983 – and haven’t skipped a year since. Prepare for a big bath of heavyweight sounds and an early dip in the deep end of dub.

Please note that this act is part of Dekmantel at Dawn, which is exclusively accessible to weekend ticket holders.', 'https://dekmantelfestival.com/artists/channel-one', 'festival:dekmantel-2026', 'Bass for breakfast? Yes, please! Last with us in ’22, we’re thrilled to have Channel One back in the forest – this time for a special morning session as part of our At Dawn programme. One of the UK’s most beloved and respected reggae sound systems, Channel One is comprised of DJ Mikey Dread, MC Macky Banton and MC Ras Sherby. Formed in the late seventies, they first played London’s Notting Hill Carnival in 1983 – and haven’t skipped a year since. Prepare for a big bath of heavyweight sounds and an early dip in the deep end of dub.

Please note that this act is part of Dekmantel at Dawn, which is exclusively accessible to weekend ticket holders.')
