  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Al Wootton & Azu Tiwaline', 'al wootton & azu tiwaline', false, 'Azu Tiwaline and Al Wootton meet at the intersection of ritual and low-end pressure. Rooted in Sahrawi musical traditions and contemporary electronic practice, their collaboration crosses borders – geographical, cultural, and sonic. Azu Tiwaline’s voice and compositions draw on Amazigh heritage and the lived realities of the Sahrawi diaspora, carrying histories of resistance and endurance. While Al Wootton, emerging from the fringes of British bass culture, brings a finely tuned sense of texture and space shaped by years working across dub, experimental electronics, and improvisation. Together, they craft a synergy that feels both grounded and expansive: ceremonial yet propulsive, where traditional melodies, hand-played instruments, and digital tools lock into hypnotic motion. Resisting categorisation, their music is folkloric and forward-facing – emotionally charged and deeply attentive to rhythm as a carrier of memory, struggle, and connection.', 'https://dekmantelfestival.com/artists/azu-tiwaline-al-wootton', 'festival:dekmantel-2026', 'Azu Tiwaline and Al Wootton meet at the intersection of ritual and low-end pressure. Rooted in Sahrawi musical traditions and contemporary electronic practice, their collaboration crosses borders – geographical, cultural, and sonic. Azu Tiwaline’s voice and compositions draw on Amazigh heritage and the lived realities of the Sahrawi diaspora, carrying histories of resistance and endurance. While Al Wootton, emerging from the fringes of British bass culture, brings a finely tuned sense of texture and space shaped by years working across dub, experimental electronics, and improvisation. Together, they craft a synergy that feels both grounded and expansive: ceremonial yet propulsive, where traditional melodies, hand-played instruments, and digital tools lock into hypnotic motion. Resisting categorisation, their music is folkloric and forward-facing – emotionally charged and deeply attentive to rhythm as a carrier of memory, struggle, and connection.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Mia Koden', 'mia koden', false, 'Mia Koden is all about the low end. Drawing on her South Sudanese heritage, years spent in Ghana and Nigeria, and the influence of London’s sound system culture, she balances tradition with rhythmic invention – reshaping heavy sounds into intense, playful, and irresistible new forms. She often laces her own tracks into her sets, channeling a raw, percussive approach that cuts through dubstep, 2-step, breaks, and techno. Following multiple appearances at the festival, it’s safe to say she is firmly part of the Dekmantel family: a vital, uncompromising selector with bass-and-percussion-driven instincts and a taste for the unexpected.', 'https://dekmantelfestival.com/artists/mia-koden', 'festival:dekmantel-2026', 'Mia Koden is all about the low end. Drawing on her South Sudanese heritage, years spent in Ghana and Nigeria, and the influence of London’s sound system culture, she balances tradition with rhythmic invention – reshaping heavy sounds into intense, playful, and irresistible new forms. She often laces her own tracks into her sets, channeling a raw, percussive approach that cuts through dubstep, 2-step, breaks, and techno. Following multiple appearances at the festival, it’s safe to say she is firmly part of the Dekmantel family: a vital, uncompromising selector with bass-and-percussion-driven instincts and a taste for the unexpected.')
