  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('The Bug & Warrior Queen', 'the bug & warrior queen', false, 'Returning to the forest for a live performance, please welcome UK heavyweight The Bug. Known for his gloomy, earth-shattering sound, Kevin Martin moves between dub, dancehall, grime and industrial – a blend described as ‘toxic dancehall’ – since the late ’90s. Any sound The Bug produces is made for the live stage: “I’ve always been addicted to the physicality and intensity of sound. I started The Bug because I wanted to make music for a soundsystem I had in storage, and the live experience of The Bug has always been something I wanted to reflect on record.” This time around, The Boss is joined by Jamaican MC, singer and writer Annette Henry, better known as Warrior Queen. Bridging reggae, dancehall and club music with an almost prophetic spirit in her fiery vocals, Warrior Queen has previously collaborated with the likes of Skream and Vex’d. Unlike The Bug, she has never performed at Dekmantel Festival before.', 'https://dekmantelfestival.com/artists/the-bug-warrior-queen', 'festival:dekmantel-2026', 'Returning to the forest for a live performance, please welcome UK heavyweight The Bug. Known for his gloomy, earth-shattering sound, Kevin Martin moves between dub, dancehall, grime and industrial – a blend described as ‘toxic dancehall’ – since the late ’90s. Any sound The Bug produces is made for the live stage: “I’ve always been addicted to the physicality and intensity of sound. I started The Bug because I wanted to make music for a soundsystem I had in storage, and the live experience of The Bug has always been something I wanted to reflect on record.” This time around, The Boss is joined by Jamaican MC, singer and writer Annette Henry, better known as Warrior Queen. Bridging reggae, dancehall and club music with an almost prophetic spirit in her fiery vocals, Warrior Queen has previously collaborated with the likes of Skream and Vex’d. Unlike The Bug, she has never performed at Dekmantel Festival before.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Colin Benders', 'colin benders', false, 'It’s difficult not to get blown away by Colin Benders. A master of modular techno, the Dutch artist – who first made a name for himself under the Kyteman moniker – takes live improvisation to a whole new level. When Benders takes to the booth, there’s always a sense of duality. On the one hand, his performances are raw, tense, instinctive and visceral. At the same time, his live hardware sounds hypnotise and mesmerise, reaching as far as the meditative and transcendental. For Dekmantel ’26, Colin Benders will perform a special At Dawn show.

Please note that this act is part of Dekmantel at Dawn, which is exclusively accessible to weekend ticket holders.', 'https://dekmantelfestival.com/artists/colin-benders', 'festival:dekmantel-2026', 'It’s difficult not to get blown away by Colin Benders. A master of modular techno, the Dutch artist – who first made a name for himself under the Kyteman moniker – takes live improvisation to a whole new level. When Benders takes to the booth, there’s always a sense of duality. On the one hand, his performances are raw, tense, instinctive and visceral. At the same time, his live hardware sounds hypnotise and mesmerise, reaching as far as the meditative and transcendental. For Dekmantel ’26, Colin Benders will perform a special At Dawn show.

Please note that this act is part of Dekmantel at Dawn, which is exclusively accessible to weekend ticket holders.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
