    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Ben UFO', 'ben ufo', false, 'One of the architects of contemporary electronic sound, Ben UFO is a London-based DJ celebrated for his restless, wide-angle approach to the dancefloor. His swift, finely judged mixing journeys from one side of the UK club music spectrum to the other, gliding across garage, grime, and dubstep, and bass, often within the same breath. As co-founder of Hessle Audio, the imprint he has run alongside Pearson Sound and Pangaea since 2007, his curatorial vision has left a lasting imprint through landmark releases by artists such as James Blake, Blawan, and the Hessle trio themselves. A formative presence on Rinse FM – the radio platform synonymous with modern British bass culture – Ben UFO honed his craft through deep listening, patience, and sound-system intuition.', 'https://dekmantelfestival.com/artists/ben-ufo', 'festival:dekmantel-2026', 'One of the architects of contemporary electronic sound, Ben UFO is a London-based DJ celebrated for his restless, wide-angle approach to the dancefloor. His swift, finely judged mixing journeys from one side of the UK club music spectrum to the other, gliding across garage, grime, and dubstep, and bass, often within the same breath. As co-founder of Hessle Audio, the imprint he has run alongside Pearson Sound and Pangaea since 2007, his curatorial vision has left a lasting imprint through landmark releases by artists such as James Blake, Blawan, and the Hessle trio themselves. A formative presence on Rinse FM – the radio platform synonymous with modern British bass culture – Ben UFO honed his craft through deep listening, patience, and sound-system intuition.')
  ON CONFLICT (sort_name) DO UPDATE SET
