  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('CCL', 'ccl', false, 'A master of opaque moods and rhythmic chicanes, CCL triggers combustive shifts through wiggle-steppers, trip-no, dub-core, cowgirl breaks, trip funk and beyond. While many DJs traverse genres, few do so with such elasticity; CCL glides between tempos and textures — from speedy 160 BPM to the hot, slung momentum of 100 — with transitions that feel both mischievous and breathlessly precise. Drawing on roots in Bristol and North American DIY scenes — as a talent buyer, festival organiser and obsessive record collector — they approach the dancefloor as a space of fluidity and liminality, opening wormholes between eras, regions and styles. On the RADAR stage, CCL appears at their most unbound; for a more focused approach, catch their Invisible Cities showcase, a mix inspired by their forthcoming project on Dekmantel Records.', 'https://dekmantelfestival.com/artists/ccl-2', 'festival:dekmantel-2026', 'A master of opaque moods and rhythmic chicanes, CCL triggers combustive shifts through wiggle-steppers, trip-no, dub-core, cowgirl breaks, trip funk and beyond. While many DJs traverse genres, few do so with such elasticity; CCL glides between tempos and textures — from speedy 160 BPM to the hot, slung momentum of 100 — with transitions that feel both mischievous and breathlessly precise. Drawing on roots in Bristol and North American DIY scenes — as a talent buyer, festival organiser and obsessive record collector — they approach the dancefloor as a space of fluidity and liminality, opening wormholes between eras, regions and styles. On the RADAR stage, CCL appears at their most unbound; for a more focused approach, catch their Invisible Cities showcase, a mix inspired by their forthcoming project on Dekmantel Records.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Woody92', 'woody92', false, 'A multi-disciplinary artist at heart, Woody92 plays by his own creative rules. Both clubbers and critics have come to adore the way this Dutch DJ weaves together psychoactive strains of leftfield electronics, hypnotic techno and radiant minimalism – resulting in a time-suspending sound that’s hard and unrelenting, yet shimmers with musical intelligence and oddball originality. Since ’21, Woody92 also runs Omen Wapta, the label where his zeal for reinterpreting electronic music comes together with experimental art and design. It’s safe to say this talent is becoming a pillar of the Netherland’s electronic landscape, with a heartfelt vision that travels far beyond.', 'https://dekmantelfestival.com/artists/woody92', 'festival:dekmantel-2026', 'A multi-disciplinary artist at heart, Woody92 plays by his own creative rules. Both clubbers and critics have come to adore the way this Dutch DJ weaves together psychoactive strains of leftfield electronics, hypnotic techno and radiant minimalism – resulting in a time-suspending sound that’s hard and unrelenting, yet shimmers with musical intelligence and oddball originality. Since ’21, Woody92 also runs Omen Wapta, the label where his zeal for reinterpreting electronic music comes together with experimental art and design. It’s safe to say this talent is becoming a pillar of the Netherland’s electronic landscape, with a heartfelt vision that travels far beyond.')
