  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Amoral', 'amoral', false, 'Amsterdam’s AMORAL has quickly made her way to some of techno’s most loved spaces, from New York’s BASEMENT to regular appearances at Berghain. Back in Amsterdam, she runs the clubbers’ favourite event series Eerste Communie, where she is also a resident. In true Eerste Communie style, AMORAL’s sound is endlessly rolling and vibrant, with a euphoric undertone. After showcasing her unique take on techno at Dekmantel Ten and in our UFO last year, we’re gearing up for another trip through her carefully crafted wormhole.', 'https://dekmantelfestival.com/artists/amoral-2', 'festival:dekmantel-2026', 'Amsterdam’s AMORAL has quickly made her way to some of techno’s most loved spaces, from New York’s BASEMENT to regular appearances at Berghain. Back in Amsterdam, she runs the clubbers’ favourite event series Eerste Communie, where she is also a resident. In true Eerste Communie style, AMORAL’s sound is endlessly rolling and vibrant, with a euphoric undertone. After showcasing her unique take on techno at Dekmantel Ten and in our UFO last year, we’re gearing up for another trip through her carefully crafted wormhole.')
