  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Nørbak & Surgeon', 'nørbak & surgeon', false, 'A meeting of two of techno’s sharpest minds, Nørbak and Surgeon come together on the RADAR stage for a rare live performance. Portuguese producer Nørbak is known for precise sound design and hypnotic structures, where dense textures and shifting rhythms unfold with careful control. Part of a new generation of ambitious artists, his work resonates with a lineage shaped by figures such as Surgeon — a central force in British techno for more than three decades who continues to expand the form through live electronics, modular synthesis and collective projects. Before stepping up to RADAR, Surgeon also appears with James Holden for the Dekmantel Festival opening ceremony, setting the weekend in motion.', 'https://dekmantelfestival.com/artists/nørbak-surgeon-live', 'festival:dekmantel-2026', 'A meeting of two of techno’s sharpest minds, Nørbak and Surgeon come together on the RADAR stage for a rare live performance. Portuguese producer Nørbak is known for precise sound design and hypnotic structures, where dense textures and shifting rhythms unfold with careful control. Part of a new generation of ambitious artists, his work resonates with a lineage shaped by figures such as Surgeon — a central force in British techno for more than three decades who continues to expand the form through live electronics, modular synthesis and collective projects. Before stepping up to RADAR, Surgeon also appears with James Holden for the Dekmantel Festival opening ceremony, setting the weekend in motion.')
  ON CONFLICT (sort_name) DO UPDATE SET
