    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Wata Igarashi', 'wata igarashi', false, 'Wata Igarashi takes to the RADAR stage, bringing his signature strain of crystalline techno into focus. The Dekmantel label affiliate — who also appears for a B2B with DJ Nobu during the festival — carves out spiralling sound worlds built on tunnelling basslines and cascading arpeggiator patterns. Drawing on a deep knowledge of psychedelia and a hardware-heavy studio practice, his mixes favour slow harmonic shifts and carefully layered tonal movement. Under his steady hand, frequencies and intensities are shaped with measured control, easing the dancefloor into a dreamlike state where luminous, cloud-like synths cut through dense rhythmic pressure.', 'https://dekmantelfestival.com/artists/wata-igarashi', 'festival:dekmantel-2026', 'Wata Igarashi takes to the RADAR stage, bringing his signature strain of crystalline techno into focus. The Dekmantel label affiliate — who also appears for a B2B with DJ Nobu during the festival — carves out spiralling sound worlds built on tunnelling basslines and cascading arpeggiator patterns. Drawing on a deep knowledge of psychedelia and a hardware-heavy studio practice, his mixes favour slow harmonic shifts and carefully layered tonal movement. Under his steady hand, frequencies and intensities are shaped with measured control, easing the dancefloor into a dreamlike state where luminous, cloud-like synths cut through dense rhythmic pressure.')
