    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Rene Wise', 'rene wise', false, 'Moving Pressure label head Rene Wise is drawn to polyrhythms. With an astute ability to layer tracks over multiple decks, he draws on his background in percussion, taking cues from his Iranian father, a professional drummer. Channelling this musical heritage through his sparse-but-driving techno, Wise''s ''quality over quantity'' mindset has seen him become a fixture on respected labels like Mote Evolver and BluePrint, collaborating with many industry luminaries. As a DJ, his pure and passionate approach has earned him spots at revered venues like Berghain and Fabric, along with a residency at the esteemed Dutch underground Eerste Communie parties. After a mind-melting set in our UFO during Dekmantel Ten, Rene Wise returns to Amsterdamse Bos.', 'https://dekmantelfestival.com/artists/rene-wise', 'festival:dekmantel-2026', 'Moving Pressure label head Rene Wise is drawn to polyrhythms. With an astute ability to layer tracks over multiple decks, he draws on his background in percussion, taking cues from his Iranian father, a professional drummer. Channelling this musical heritage through his sparse-but-driving techno, Wise''s ''quality over quantity'' mindset has seen him become a fixture on respected labels like Mote Evolver and BluePrint, collaborating with many industry luminaries. As a DJ, his pure and passionate approach has earned him spots at revered venues like Berghain and Fabric, along with a residency at the esteemed Dutch underground Eerste Communie parties. After a mind-melting set in our UFO during Dekmantel Ten, Rene Wise returns to Amsterdamse Bos.')
