    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Sandrien', 'sandrien', false, 'Thanks to former residencies at some of Amsterdam’s most celebrated (but now-closed) clubs, her role as co-founder of Is Burning, and a renowned record collection, Sandrien has become a local hero. With more than twenty years in the game, her versatile take on techno has carried her far beyond the city: from Japan to Tbilisi to far beyond. Deep yet driving, blending classics with futuristic sounds, her head-spinning selections have earned her the title of a DJ’s favourite DJ. Remarkably, she brings the same mastery, and yet another stash of hidden gems, to her house music sets.', 'https://dekmantelfestival.com/artists/sandrien', 'festival:dekmantel-2026', 'Thanks to former residencies at some of Amsterdam’s most celebrated (but now-closed) clubs, her role as co-founder of Is Burning, and a renowned record collection, Sandrien has become a local hero. With more than twenty years in the game, her versatile take on techno has carried her far beyond the city: from Japan to Tbilisi to far beyond. Deep yet driving, blending classics with futuristic sounds, her head-spinning selections have earned her the title of a DJ’s favourite DJ. Remarkably, she brings the same mastery, and yet another stash of hidden gems, to her house music sets.')
