  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Doudou MD', 'doudou md', false, 'A familiar force within the Dekmantel universe, Doudou MD returns with the assurance of an artist whose range and intuition continue to deepen. Known for sets that refuse repetition, her sonic language moves fluidly between house, swung techno, UK garage, dubwise pressure, and left-field electronics, always guided by rhythm, groove, and feel rather than formula. Born to a Dutch classical singer and pianist and a Congolese percussionist, her musical lineage is palpable: percussion leads, melodies spiral, and time bends. Working primarily with vinyl, Doudou MD draws from the rich archives of British, American, and German electronic music, layering hypnotic structures with a spiritual charge. With long-standing ties to Utrecht’s SlapFunk and regular appearances with Amsterdam’s VBX, she has firmly established herself as a selector defined by depth, curiosity, and forward momentum.', 'https://dekmantelfestival.com/artists/doudou-md-2', 'festival:dekmantel-2026', 'A familiar force within the Dekmantel universe, Doudou MD returns with the assurance of an artist whose range and intuition continue to deepen. Known for sets that refuse repetition, her sonic language moves fluidly between house, swung techno, UK garage, dubwise pressure, and left-field electronics, always guided by rhythm, groove, and feel rather than formula. Born to a Dutch classical singer and pianist and a Congolese percussionist, her musical lineage is palpable: percussion leads, melodies spiral, and time bends. Working primarily with vinyl, Doudou MD draws from the rich archives of British, American, and German electronic music, layering hypnotic structures with a spiritual charge. With long-standing ties to Utrecht’s SlapFunk and regular appearances with Amsterdam’s VBX, she has firmly established herself as a selector defined by depth, curiosity, and forward momentum.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Marcel Dettmann', 'marcel dettmann', false, 'Marcel Dettmann’s name is synonymous with Berlin’s techno lineage, yet for Dekmantel 2026 he opens a different door. His house sets are not nostalgic detours but precision-built journeys: stripped-back, rhythm-driven, and quietly subversive. Drawing on early ’90s club energy, warped grooves, and tracks that sit just off-centre, Dettmann threads momentum with restraint, letting swing, pressure, and texture do the heavy lifting. A longtime resident of Berghain and a central figure in shaping its sound, he approaches the dancefloor as a curator as much as a DJ. Across decades of releases, label projects, and work spanning contemporary art, film, and performance, Dettmann has continually expanded what dance music can be – making this house set less a stylistic shift than a rare glimpse into the full breadth of his musical thinking.', 'https://dekmantelfestival.com/artists/marcel-dettmann', 'festival:dekmantel-2026', 'Marcel Dettmann’s name is synonymous with Berlin’s techno lineage, yet for Dekmantel 2026 he opens a different door. His house sets are not nostalgic detours but precision-built journeys: stripped-back, rhythm-driven, and quietly subversive. Drawing on early ’90s club energy, warped grooves, and tracks that sit just off-centre, Dettmann threads momentum with restraint, letting swing, pressure, and texture do the heavy lifting. A longtime resident of Berghain and a central figure in shaping its sound, he approaches the dancefloor as a curator as much as a DJ. Across decades of releases, label projects, and work spanning contemporary art, film, and performance, Dettmann has continually expanded what dance music can be – making this house set less a stylistic shift than a rare glimpse into the full breadth of his musical thinking.')
