  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Job Jobse & Palms Trax', 'job jobse & palms trax', false, 'Palms Trax and Job Jobse join forces for a much-awaited back-to-back – their very first at Dekmantel! United by a shared love of joyful excess – big-hearted house and disco, electrifying techno, and tripped-out trance – expect a set that’s fast, loose, and gloriously unpredictable. A presence at the festival since its earliest days and a longstanding affiliate of the label, Palms Trax, the Berlin-based British selector, lights up dancefloors worldwide with marathon-length mixes and his much-adored NTS radio show. Meanwhile, Job Jobse emerged from former Amsterdam institution Trouw, earning acclaim for his ecstatic, high-energy presence alongside the celebrated Strangelove party series and Planet Strangelove label. Expect cheeky curveballs throughout and a dancefloor running at full tilt.', 'https://dekmantelfestival.com/artists/job-jobse-palms-trax', 'festival:dekmantel-2026', 'Palms Trax and Job Jobse join forces for a much-awaited back-to-back – their very first at Dekmantel! United by a shared love of joyful excess – big-hearted house and disco, electrifying techno, and tripped-out trance – expect a set that’s fast, loose, and gloriously unpredictable. A presence at the festival since its earliest days and a longstanding affiliate of the label, Palms Trax, the Berlin-based British selector, lights up dancefloors worldwide with marathon-length mixes and his much-adored NTS radio show. Meanwhile, Job Jobse emerged from former Amsterdam institution Trouw, earning acclaim for his ecstatic, high-energy presence alongside the celebrated Strangelove party series and Planet Strangelove label. Expect cheeky curveballs throughout and a dancefloor running at full tilt.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
