    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Benny Rodrigues', 'benny rodrigues', false, 'One of the greatest disc jockeys to ever come from Dutch soil, please welcome Benny Rodrigues to Dekmantel ’26. Last year, Rotterdam’s one and only joined us under his ROD alias – teaming up with Sterac to flood UFO 1 with unrelenting techno. This summer, he returns under his original moniker, which means you can expect a higher dose of groove‑laden, high-adrenaline (tech‑)house, with irresistible influences from the realms of Detroit, minimal, and acid. Rodrigues was previously named The Netherlands’ most influential DJ – and there’s good reason for it. Once you’ve experienced him in action, the party never stops.', 'https://dekmantelfestival.com/artists/benny-rodrigues', 'festival:dekmantel-2026', 'One of the greatest disc jockeys to ever come from Dutch soil, please welcome Benny Rodrigues to Dekmantel ’26. Last year, Rotterdam’s one and only joined us under his ROD alias – teaming up with Sterac to flood UFO 1 with unrelenting techno. This summer, he returns under his original moniker, which means you can expect a higher dose of groove‑laden, high-adrenaline (tech‑)house, with irresistible influences from the realms of Detroit, minimal, and acid. Rodrigues was previously named The Netherlands’ most influential DJ – and there’s good reason for it. Once you’ve experienced him in action, the party never stops.')
