  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Lea Occhi', 'lea occhi', false, 'For Lea Occhi, music has always been a place to land. Her early memories are scored by jazz, soul, and chansons; later, as a teenager, that quiet devotion tipped into a fascination with electronica. The French DJ, now residing in Amsterdam, works with tension and release as raw material. Rooted in techno yet open in shape, her sets roll through heady, hypnotic rhythms, earthy textures, and pockets of air, guided by a finely tuned sense of timing and atmosphere. A digger by instinct, Lea has a particular talent for churning up unique blends of micro-house, deep, and ambient tracks. In 2017, she co-founded Spectrum Waves, a Paris-based queer collective centred on safer spaces, care, and community – values that continue to pulse through her sound.', 'https://dekmantelfestival.com/artists/lea-occhi', 'festival:dekmantel-2026', 'For Lea Occhi, music has always been a place to land. Her early memories are scored by jazz, soul, and chansons; later, as a teenager, that quiet devotion tipped into a fascination with electronica. The French DJ, now residing in Amsterdam, works with tension and release as raw material. Rooted in techno yet open in shape, her sets roll through heady, hypnotic rhythms, earthy textures, and pockets of air, guided by a finely tuned sense of timing and atmosphere. A digger by instinct, Lea has a particular talent for churning up unique blends of micro-house, deep, and ambient tracks. In 2017, she co-founded Spectrum Waves, a Paris-based queer collective centred on safer spaces, care, and community – values that continue to pulse through her sound.')
