  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Ogázon & Philippa Pacho', 'ogázon & philippa pacho', false, 'Two DJs who’ve got electronic music in a headlock right now? Ogazón and Philippa Pacho, of course – and they’re coming at you in one booth. Ogazón (hailing from Luxembourg via Amsterdam and Berlin) has steadily built a global reputation for her sharp, floor-first approach, drawing on a wide spectrum of quality house and techno and a thorough, personal understanding of nightlife. Her sets, like a brooding storm, are known for their precision, energy and ability to subtly lift a crowd to higher planes. Philippa Pacho (Sweden-born, Berlin-based) brings a contrasting yet complementary intensity that’s hypnotic and groove-driven. Her signature sound blends the darker shades of techno, electro and trance with a sleek sense of texture and timing. Wherever these two plan to take you, you’ll want to be there.', 'https://dekmantelfestival.com/artists/ogázon-philippa-pacho', 'festival:dekmantel-2026', 'Two DJs who’ve got electronic music in a headlock right now? Ogazón and Philippa Pacho, of course – and they’re coming at you in one booth. Ogazón (hailing from Luxembourg via Amsterdam and Berlin) has steadily built a global reputation for her sharp, floor-first approach, drawing on a wide spectrum of quality house and techno and a thorough, personal understanding of nightlife. Her sets, like a brooding storm, are known for their precision, energy and ability to subtly lift a crowd to higher planes. Philippa Pacho (Sweden-born, Berlin-based) brings a contrasting yet complementary intensity that’s hypnotic and groove-driven. Her signature sound blends the darker shades of techno, electro and trance with a sleek sense of texture and timing. Wherever these two plan to take you, you’ll want to be there.')
  ON CONFLICT (sort_name) DO UPDATE SET
