  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Lady Starlight & Sterac', 'lady starlight & sterac', false, 'Seamlessly blending banging techno, industrial, punk and acid, Lady Starlight stands as a singular force in the US underground. A devoted hardware and vinyl enthusiast, her path has taken her far beyond it – into Europe, and even into pop, through her longstanding collaboration with that other world-famous Lady from NYC. At Dekmantel Festival ’26, Starlight will play a special show with STERAC, the local electronic music pioneer and producer also known as Steve Rachmad. When these two trailblazers unite, expect a no-nonsense live excursion into techno’s deep, dark, head- and body-rattling realms.', 'https://dekmantelfestival.com/artists/lady-starlight-sterac-live', 'festival:dekmantel-2026', 'Seamlessly blending banging techno, industrial, punk and acid, Lady Starlight stands as a singular force in the US underground. A devoted hardware and vinyl enthusiast, her path has taken her far beyond it – into Europe, and even into pop, through her longstanding collaboration with that other world-famous Lady from NYC. At Dekmantel Festival ’26, Starlight will play a special show with STERAC, the local electronic music pioneer and producer also known as Steve Rachmad. When these two trailblazers unite, expect a no-nonsense live excursion into techno’s deep, dark, head- and body-rattling realms.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('DVS1', 'dvs1', false, 'What can we say about DVS1 that hasn’t already been said? Zak Khutoretsky embodies the ever-beating, unrelenting heart of techno – whether through his deep, immersive and endlessly expansive DJ sets, his stripped-back yet richly detailed productions on the world’s most respected labels, or through scene-shaping projects such as HUSH and Aslice. A storyteller who has dedicated his life to nurturing underground electronic music and its community while pushing back against commercial pressures, his vision remains as uncompromising today as it was 30 years ago. Needless to say, we can’t imagine Dekmantel Festival without his dark arts.', 'https://dekmantelfestival.com/artists/dvs1', 'festival:dekmantel-2026', 'What can we say about DVS1 that hasn’t already been said? Zak Khutoretsky embodies the ever-beating, unrelenting heart of techno – whether through his deep, immersive and endlessly expansive DJ sets, his stripped-back yet richly detailed productions on the world’s most respected labels, or through scene-shaping projects such as HUSH and Aslice. A storyteller who has dedicated his life to nurturing underground electronic music and its community while pushing back against commercial pressures, his vision remains as uncompromising today as it was 30 years ago. Needless to say, we can’t imagine Dekmantel Festival without his dark arts.')
