  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('DJ Nobu & Wata Igarashi', 'dj nobu & wata igarashi', false, 'Nobody quite does techno like these two Japanese torchbearers. On the one hand: Nobu, a DJ with no fixed style but a rare ability to draw from a fluid world of music – and construct his own. Based in Tokyo, Nobu is something of a cult figure with decades of experience, distilled through his acclaimed Future Terror party, his Bitta label and his stellar productions. On the other: Wata Igarashi, whose crystalline deep-end techno is characterised by tunnelling rhythms and arpeggio sequences. In the past year, Igarashi released his long-awaited LP, ‘My Supernova’, on Dekmantel Records. Now, he joins DJ Nobu for a B2B session bound to melt the mind – generating both energy and emotion.', 'https://dekmantelfestival.com/artists/dj-nobu-wata-igarashi', 'festival:dekmantel-2026', 'Nobody quite does techno like these two Japanese torchbearers. On the one hand: Nobu, a DJ with no fixed style but a rare ability to draw from a fluid world of music – and construct his own. Based in Tokyo, Nobu is something of a cult figure with decades of experience, distilled through his acclaimed Future Terror party, his Bitta label and his stellar productions. On the other: Wata Igarashi, whose crystalline deep-end techno is characterised by tunnelling rhythms and arpeggio sequences. In the past year, Igarashi released his long-awaited LP, ‘My Supernova’, on Dekmantel Records. Now, he joins DJ Nobu for a B2B session bound to melt the mind – generating both energy and emotion.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Neska', 'neska', false, 'Peppered with twists, turns, and elegant surprises, Neska builds mixes through careful excavation. Basque-born and shaped by backgrounds in classical, jazz, and punk, her DJing folds disparate lineages into a cohesive logic – where rhythm bends, forms dissolve, and expectations are quietly subverted. Now based in Amsterdam via Barcelona, she has appeared across major Spanish festivals and Dutch clubs, carving out a reputation for sets that are psychedelic and grounded in physical presence, drawing from dub and experimental pulse. Beyond the booth, she curates fauna & flora, a multidisciplinary platform connecting electronic music with site-responsive art installations, and hosts Neskafe, a forward-looking residency on Echobox Radio. Attentive to detail, pacing, and atmosphere, Neska treats the dancefloor as a space for curiosity and sustained attention.', 'https://dekmantelfestival.com/artists/neska', 'festival:dekmantel-2026', 'Peppered with twists, turns, and elegant surprises, Neska builds mixes through careful excavation. Basque-born and shaped by backgrounds in classical, jazz, and punk, her DJing folds disparate lineages into a cohesive logic – where rhythm bends, forms dissolve, and expectations are quietly subverted. Now based in Amsterdam via Barcelona, she has appeared across major Spanish festivals and Dutch clubs, carving out a reputation for sets that are psychedelic and grounded in physical presence, drawing from dub and experimental pulse. Beyond the booth, she curates fauna & flora, a multidisciplinary platform connecting electronic music with site-responsive art installations, and hosts Neskafe, a forward-looking residency on Echobox Radio. Attentive to detail, pacing, and atmosphere, Neska treats the dancefloor as a space for curiosity and sustained attention.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('The Black Dog', 'the black dog', false, 'The Black Dog are practically synonymous with intelligent dance music, or IDM – the strain of thoughtful electronica they helped bring into being in the early 1990s. Emerging from Sheffield, England, the group’s influential releases on Warp Records – including Bytes (1993) and Spanners (1995) – fused textured rhythms, atmospheric density, and experimental structure into a new electronic vocabulary that, more than thirty years on, continues to serve as a blueprint for producers worldwide. In recent years, The Black Dog have continued to push steadily forward, exploring ambient, techno, and conceptual terrain through albums such as Music for Real Airports (2010) and Other, Like Me (2024), extending practice while retaining a sharply political and textural edge. Following the loss of founding member Ken Downie in December 2025, their live performance at Dekmantel 2026 is sure to honour his enduring legacy: a restless spirit and a lifelong dedication to expanding music''s possibilities.', 'https://dekmantelfestival.com/artists/the-black-dog-live', 'festival:dekmantel-2026', 'The Black Dog are practically synonymous with intelligent dance music, or IDM – the strain of thoughtful electronica they helped bring into being in the early 1990s. Emerging from Sheffield, England, the group’s influential releases on Warp Records – including Bytes (1993) and Spanners (1995) – fused textured rhythms, atmospheric density, and experimental structure into a new electronic vocabulary that, more than thirty years on, continues to serve as a blueprint for producers worldwide. In recent years, The Black Dog have continued to push steadily forward, exploring ambient, techno, and conceptual terrain through albums such as Music for Real Airports (2010) and Other, Like Me (2024), extending practice while retaining a sharply political and textural edge. Following the loss of founding member Ken Downie in December 2025, their live performance at Dekmantel 2026 is sure to honour his enduring legacy: a restless spirit and a lifelong dedication to expanding music''s possibilities.')
