  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Gyrofield', 'gyrofield', false, 'Very few artists in contemporary drum & bass have experienced a rise as rapid – or as closely watched – as Gyrofield. Born and raised in Hong Kong, Kiana Li has carved out a singular presence through releases that veer from dystopian, industrial-weight pressure to psychedelic, off-grid explorations, resisting fixed genre logic at every turn. A self-described egirl with a soft spot for cats, Gyrofield pairs sharp technical precision with an instinct for narrative world-building, producing tracks that feel as psychologically charged as they are physically forceful. Whether operating at breakneck tempos or dissolving rhythm altogether, her work – both behind the DJ booth and in the studio – is defined by constant mutation. To follow Gyrofield is to accept that she will never settle into one sound, one tempo, or one expectation – only an ever-shifting system, perpetually reconfiguring itself in real time.', 'https://dekmantelfestival.com/artists/gyrofield', 'festival:dekmantel-2026', 'Very few artists in contemporary drum & bass have experienced a rise as rapid – or as closely watched – as Gyrofield. Born and raised in Hong Kong, Kiana Li has carved out a singular presence through releases that veer from dystopian, industrial-weight pressure to psychedelic, off-grid explorations, resisting fixed genre logic at every turn. A self-described egirl with a soft spot for cats, Gyrofield pairs sharp technical precision with an instinct for narrative world-building, producing tracks that feel as psychologically charged as they are physically forceful. Whether operating at breakneck tempos or dissolving rhythm altogether, her work – both behind the DJ booth and in the studio – is defined by constant mutation. To follow Gyrofield is to accept that she will never settle into one sound, one tempo, or one expectation – only an ever-shifting system, perpetually reconfiguring itself in real time.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Dopplereffekt', 'dopplereffekt', false, 'Situated at the intersection of electro, techno, and quantum physics, Dopplereffekt function less as performers than as system engineers. Emerging from Detroit in the mid-1990s, the project was founded by Gerald Donald following his work with Drexciya, alongside collaborators such as Rudolf Klorzeiger, To Nhan Le Thi, and Beatrice Ottmann. Over three decades, their output has carried forward Detroit’s sci-fi tradition through sound, exploring automation and human obsolescence via austere rhythms and synthetic voices. To witness them live is to encounter the place where music and science meet – electronica at its most rigorous and conceptual: precision over nostalgia, electro as experiment, and the dancefloor as laboratory.', 'https://dekmantelfestival.com/artists/dopplereffekt', 'festival:dekmantel-2026', 'Situated at the intersection of electro, techno, and quantum physics, Dopplereffekt function less as performers than as system engineers. Emerging from Detroit in the mid-1990s, the project was founded by Gerald Donald following his work with Drexciya, alongside collaborators such as Rudolf Klorzeiger, To Nhan Le Thi, and Beatrice Ottmann. Over three decades, their output has carried forward Detroit’s sci-fi tradition through sound, exploring automation and human obsolescence via austere rhythms and synthetic voices. To witness them live is to encounter the place where music and science meet – electronica at its most rigorous and conceptual: precision over nostalgia, electro as experiment, and the dancefloor as laboratory.')
  ON CONFLICT (sort_name) DO UPDATE SET
