  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Helena Hauff & L.F.T.', 'helena hauff & l.f.t.', false, 'Helena Hauff has been with us since the very beginning of Dekmantel Festival. Her idiosyncratic blend of electro, techno, acid and EBM is not only ice-cold and hard-edged – it also revs with an undiluted passion for the origins (and future) of machine music. In recent months, the German artist revived her Black Sites moniker with F#X, releasing their first collaborative record in a decade on Tresor. This summer, Hauff teams up with fellow Hamburg-hailing artist L.F.T.. Short for Love First Tears, this Golden Pudel resident blends new wave, techno and break-heavy electro, shaped by the distorted drum machines of The Hague and the romantic synth melodies of 1980s San Francisco. Behind the decks, L.F.T. crafts what he describes as “immersive soundscapes of futuristic dread and hopeful intensity.” As a producer, he’s released on top-notch labels such as Osàre Editions, Tresor and Mannequin.', 'https://dekmantelfestival.com/artists/helena-hauff-lft', 'festival:dekmantel-2026', 'Helena Hauff has been with us since the very beginning of Dekmantel Festival. Her idiosyncratic blend of electro, techno, acid and EBM is not only ice-cold and hard-edged – it also revs with an undiluted passion for the origins (and future) of machine music. In recent months, the German artist revived her Black Sites moniker with F#X, releasing their first collaborative record in a decade on Tresor. This summer, Hauff teams up with fellow Hamburg-hailing artist L.F.T.. Short for Love First Tears, this Golden Pudel resident blends new wave, techno and break-heavy electro, shaped by the distorted drum machines of The Hague and the romantic synth melodies of 1980s San Francisco. Behind the decks, L.F.T. crafts what he describes as “immersive soundscapes of futuristic dread and hopeful intensity.” As a producer, he’s released on top-notch labels such as Osàre Editions, Tresor and Mannequin.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Dirtylang', 'dirtylang', false, 'Few things excite us more than seeing a new crop of DJs take over the Dekmantel decks. This year, two of those emerging talents are Dirtydms and Helmond Lang – the Rotterdam artists collectively known as DirtyLang and the opening DJs of our bass haven, The Nest. Dirtydms (Alice Vink) is a DJ and designer whose inspiration is rooted in nature and human relationships, with a sound that ranges from tranquil ambient to gritty grime, IDM and footwork. Helmond Lang (Jip Boxstart) is an all-round creative spirit whose adventurous selections – regularly broadcast on Operator Radio – revolve around deep, resonant bass. What these DJs have in common is a thing for genre-bending, radical left turns and keeping listeners on their tippy toes.', 'https://dekmantelfestival.com/artists/dirtylang', 'festival:dekmantel-2026', 'Few things excite us more than seeing a new crop of DJs take over the Dekmantel decks. This year, two of those emerging talents are Dirtydms and Helmond Lang – the Rotterdam artists collectively known as DirtyLang and the opening DJs of our bass haven, The Nest. Dirtydms (Alice Vink) is a DJ and designer whose inspiration is rooted in nature and human relationships, with a sound that ranges from tranquil ambient to gritty grime, IDM and footwork. Helmond Lang (Jip Boxstart) is an all-round creative spirit whose adventurous selections – regularly broadcast on Operator Radio – revolve around deep, resonant bass. What these DJs have in common is a thing for genre-bending, radical left turns and keeping listeners on their tippy toes.')
