  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('DJ Spanish Fly', 'dj spanish fly', false, 'Legend alert! Dj Spanish Fly (real name: Antonio Kimbrough) is a foundational figure in the Memphis rap scene and one of the architects of its early sound. Starting out in the ’80s as a house DJ and bedroom rapper, he helped shift the city’s club signature from disco toward hip-hop, distributing raw, bass-heavy mixtapes that would go on to define the Memphis aesthetic – which he describes as a “wicked, 808, slow, dope groove.” His hypnotic yet aggressive rhythms and pioneering use of drum machines laid the groundwork for generations of Southern artists and a sound that’s now a global phenomenon. Today, Fly’s legacy continues to resonate as a link between local dance culture and the global evolution of electronic and rap music.', 'https://dekmantelfestival.com/artists/dj-spanish-fly', 'festival:dekmantel-2026', 'Legend alert! Dj Spanish Fly (real name: Antonio Kimbrough) is a foundational figure in the Memphis rap scene and one of the architects of its early sound. Starting out in the ’80s as a house DJ and bedroom rapper, he helped shift the city’s club signature from disco toward hip-hop, distributing raw, bass-heavy mixtapes that would go on to define the Memphis aesthetic – which he describes as a “wicked, 808, slow, dope groove.” His hypnotic yet aggressive rhythms and pioneering use of drum machines laid the groundwork for generations of Southern artists and a sound that’s now a global phenomenon. Today, Fly’s legacy continues to resonate as a link between local dance culture and the global evolution of electronic and rap music.')
  ON CONFLICT (sort_name) DO UPDATE SET
