  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Introspekt', 'introspekt', false, 'Leading the charge for the bassweight renaissance, Introspekt shows how much vitality lies in garage and dubstep when it''s approached from a fresh angle. From her early days immersed in raves in LA to the recent highlight of her debut album on the mighty Tempa, Introspekt has come far in a short time and her success is firmly rooted in her reverence for the culture. As a trans artist from America''s West Coast, her quest to reconnect garage with its queer roots ensures her sound is vital and true, and that shows in the knowledge she brings to the party each and every time she steps up.', 'https://dekmantelfestival.com/artists/introspekt', 'festival:dekmantel-2026', 'Leading the charge for the bassweight renaissance, Introspekt shows how much vitality lies in garage and dubstep when it''s approached from a fresh angle. From her early days immersed in raves in LA to the recent highlight of her debut album on the mighty Tempa, Introspekt has come far in a short time and her success is firmly rooted in her reverence for the culture. As a trans artist from America''s West Coast, her quest to reconnect garage with its queer roots ensures her sound is vital and true, and that shows in the knowledge she brings to the party each and every time she steps up.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Mala', 'mala', false, 'Few can lay claim to helping invent a new genre in the 21st century, yet Mala most definitely can. In the early 2000s, as a member of the groundbreaking DMZ collective, his mystical, sub-heavy sound captured the imagination of a generation of ravers, giving rise to the grimy, layered textures of dubstep. As dubstep spread across the globe, Mala’s focus turned toward the deeper roots of soundsystem culture, exploring connections between bass traditions and new dance music forms. Guided by principles of sustainability and collaboration, his work — as a producer, DJ and label head — continues to influence contemporary sounds and styles, pushing them into new territory. At Dekmantel ’26 Mala appears twice (dub fans rejoice!): for a solo set on RADAR and a B2B with fellow Deep Medi affiliate Sir Spyro.', 'https://dekmantelfestival.com/artists/mala', 'festival:dekmantel-2026', 'Few can lay claim to helping invent a new genre in the 21st century, yet Mala most definitely can. In the early 2000s, as a member of the groundbreaking DMZ collective, his mystical, sub-heavy sound captured the imagination of a generation of ravers, giving rise to the grimy, layered textures of dubstep. As dubstep spread across the globe, Mala’s focus turned toward the deeper roots of soundsystem culture, exploring connections between bass traditions and new dance music forms. Guided by principles of sustainability and collaboration, his work — as a producer, DJ and label head — continues to influence contemporary sounds and styles, pushing them into new territory. At Dekmantel ’26 Mala appears twice (dub fans rejoice!): for a solo set on RADAR and a B2B with fellow Deep Medi affiliate Sir Spyro.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Sir Spyro', 'sir spyro', false, 'Sir Spyro has spent over two decades shaping the evolution of grime from the inside out. As a producer, his catalogue spans heavyweight instrumentals, vocal anthems and collaborations with some of the genre’s most celebrated MCs. A seasoned broadcaster whose journey stretches from East London’s pirate networks to his landmark show on BBC Radio 1Xtra, he became a defining presence on the airwaves, renowned for his technical precision, deep musical knowledge and unmistakable energy. One of the scene’s most respected selectors, rooted in grime’s foundations but never confined by them, Spyro’s DJ sets trace a lineage through soundsystem culture, connecting dubstep, UK garage, bass music and beyond with effortless authority.', 'https://dekmantelfestival.com/artists/sir-spyro', 'festival:dekmantel-2026', 'Sir Spyro has spent over two decades shaping the evolution of grime from the inside out. As a producer, his catalogue spans heavyweight instrumentals, vocal anthems and collaborations with some of the genre’s most celebrated MCs. A seasoned broadcaster whose journey stretches from East London’s pirate networks to his landmark show on BBC Radio 1Xtra, he became a defining presence on the airwaves, renowned for his technical precision, deep musical knowledge and unmistakable energy. One of the scene’s most respected selectors, rooted in grime’s foundations but never confined by them, Spyro’s DJ sets trace a lineage through soundsystem culture, connecting dubstep, UK garage, bass music and beyond with effortless authority.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Mala & Sir Spyro', 'mala & sir spyro', false, 'Two architects of UK bass step into rare alignment. A godfather of dubstep, Mala helped define the genre in the early 2000s as part of the seminal Digital Mystikz – his duo with Coki – whose coveted records are now prized collectors’ items, trading online for hundreds of dollars. In recent years, Mala has worked tirelessly to preserve and connect low-end histories, from sound system culture to global bass lineages, through his Deep Medi Musik imprint, mixes, and cross-cultural projects. Sir Spyro, meanwhile, stands as one of grime’s most influential producers and DJs: a commanding presence whose dubs, radio shows, and uncompromising performances have shaped generations of MCs and dancefloors. To date, the pair have only gone B2B once before – unannounced, at a Deep Medi label night – making their Dekmantel 2026 appearance an exceptional encounter, where low-end frequencies, sharp transitions, and heavyweight traditions meet at full intensity.', 'https://dekmantelfestival.com/artists/mala-sir-spyro', 'festival:dekmantel-2026', 'Two architects of UK bass step into rare alignment. A godfather of dubstep, Mala helped define the genre in the early 2000s as part of the seminal Digital Mystikz – his duo with Coki – whose coveted records are now prized collectors’ items, trading online for hundreds of dollars. In recent years, Mala has worked tirelessly to preserve and connect low-end histories, from sound system culture to global bass lineages, through his Deep Medi Musik imprint, mixes, and cross-cultural projects. Sir Spyro, meanwhile, stands as one of grime’s most influential producers and DJs: a commanding presence whose dubs, radio shows, and uncompromising performances have shaped generations of MCs and dancefloors. To date, the pair have only gone B2B once before – unannounced, at a Deep Medi label night – making their Dekmantel 2026 appearance an exceptional encounter, where low-end frequencies, sharp transitions, and heavyweight traditions meet at full intensity.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Jeff Mills', 'jeff mills', false, 'Jeff Mills kicking off your festival day with a morning premiere – yes, that’s actually happening! One of the greatest artists of our time, who last closed our main stage with a mind-expanding set in ’24, will now play under the beloved willows of our Selectors stage for the very first time. Welcome to Dekmantel at Dawn.

Please note that this act is part of Dekmantel at Dawn, which is exclusively accessible to weekend ticket holders.', 'https://dekmantelfestival.com/artists/jeff-mills-debuts-stargate', 'festival:dekmantel-2026', 'Jeff Mills kicking off your festival day with a morning premiere – yes, that’s actually happening! One of the greatest artists of our time, who last closed our main stage with a mind-expanding set in ’24, will now play under the beloved willows of our Selectors stage for the very first time. Welcome to Dekmantel at Dawn.

Please note that this act is part of Dekmantel at Dawn, which is exclusively accessible to weekend ticket holders.')
