    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Fumiya Tanaka', 'fumiya tanaka', false, 'Fumiya Tanaka is a cornerstone of Japanese electronic music and a quietly influential figure in global techno. Active since the early ’90s, his work helped shape a deeper, more minimal approach to dance music, rooted in subtle restraint and long-form progression. As a DJ, Tanaka is known for sets that unfold patiently, balancing hypnotic techno with cosmic house and experimental textures. Beyond the booth, he has played a vital role in nurturing underground culture through his labels, including his current Sundance imprint, bridging scenes between Japan and Europe.', 'https://dekmantelfestival.com/artists/fumiya-tanaka', 'festival:dekmantel-2026', 'Fumiya Tanaka is a cornerstone of Japanese electronic music and a quietly influential figure in global techno. Active since the early ’90s, his work helped shape a deeper, more minimal approach to dance music, rooted in subtle restraint and long-form progression. As a DJ, Tanaka is known for sets that unfold patiently, balancing hypnotic techno with cosmic house and experimental textures. Beyond the booth, he has played a vital role in nurturing underground culture through his labels, including his current Sundance imprint, bridging scenes between Japan and Europe.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Ricardo Villalobos', 'ricardo villalobos', false, 'It’s been exactly eight years since Ricardo Villalobos last set foot in a Dekmantel booth. This summer, the Chilean-German artist returns, teleporting his elusive aura back to the Amsterdamse Bos. For those who’ve experienced Villalobos in the flesh, little introduction is needed. For those still too fresh to have a clue: come see – Hear! Inhale! Feel! – the minimal master at work. Especially at a time when club tempos and transitions feel more volatile than ever, there’s something uniquely powerful about Villalobos’s ability to work with house and techno at a microscopic level: the endless builds and blends, and the poetic, irresistible sense of groove that’s simply impossible to capture in words. Like a hypnotic, boundless jazz improvisation, his sets are minutely sculpted – slowed, sped up, shaved – and gently steered towards bliss. Villalobos doesn’t just play records; he reinvents time. We’re proud to welcome him back.', 'https://dekmantelfestival.com/artists/ricardo-villalobos', 'festival:dekmantel-2026', 'It’s been exactly eight years since Ricardo Villalobos last set foot in a Dekmantel booth. This summer, the Chilean-German artist returns, teleporting his elusive aura back to the Amsterdamse Bos. For those who’ve experienced Villalobos in the flesh, little introduction is needed. For those still too fresh to have a clue: come see – Hear! Inhale! Feel! – the minimal master at work. Especially at a time when club tempos and transitions feel more volatile than ever, there’s something uniquely powerful about Villalobos’s ability to work with house and techno at a microscopic level: the endless builds and blends, and the poetic, irresistible sense of groove that’s simply impossible to capture in words. Like a hypnotic, boundless jazz improvisation, his sets are minutely sculpted – slowed, sped up, shaved – and gently steered towards bliss. Villalobos doesn’t just play records; he reinvents time. We’re proud to welcome him back.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Konduku', 'konduku', false, 'Konduku (real name Ruben Üvez) is living proof of techno’s cerebral and expansive potential. A skilled DJ who has steadily climbed to the top, his sets – immersive, percussive and often polyrhythmic – stand out for their ability to blend and layer sounds that conjure otherworldly hypnotism and radical genre hybrids. As an equally accomplished producer, he is most commonly associated with the wondrous world of Nous’klaer, as well as DJ Nobu’s Bitta imprint and Dozzy and Neel’s Spazio Disponibile. Following last year’s standout RADAR set – which you can still enjoy on YouTube – we’re thrilled to welcome him back.', 'https://dekmantelfestival.com/artists/konduku', 'festival:dekmantel-2026', 'Konduku (real name Ruben Üvez) is living proof of techno’s cerebral and expansive potential. A skilled DJ who has steadily climbed to the top, his sets – immersive, percussive and often polyrhythmic – stand out for their ability to blend and layer sounds that conjure otherworldly hypnotism and radical genre hybrids. As an equally accomplished producer, he is most commonly associated with the wondrous world of Nous’klaer, as well as DJ Nobu’s Bitta imprint and Dozzy and Neel’s Spazio Disponibile. Following last year’s standout RADAR set – which you can still enjoy on YouTube – we’re thrilled to welcome him back.')
  ON CONFLICT (sort_name) DO UPDATE SET
