  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Trickpony', 'trickpony', false, 'Last year, we hosted the unforgettable live debut of Dekmantel regular Katie Campbell – better known as Roza Terenzi. This year, the producer returns alongside fellow Aussie producer Michael Gunson and Helsinki vocalist/producer/designer Maria Korkeila. Together, the three make up Trickpony: a self-described “unconventional prototype band” that creates sensual cyber jams with one nostalgic foot in the past and one dreamy foot in the future. Think trip-hop atmospherics, candle-lit pop, downtempo rollers and spine-tingling, hallucinatory textures. Just weeks ago, Trickpony released their divine debut EP, ‘24/7 Heaven’. Now, the trio makes its Dekmantel Festival debut.', 'https://dekmantelfestival.com/artists/trickpony-live', 'festival:dekmantel-2026', 'Last year, we hosted the unforgettable live debut of Dekmantel regular Katie Campbell – better known as Roza Terenzi. This year, the producer returns alongside fellow Aussie producer Michael Gunson and Helsinki vocalist/producer/designer Maria Korkeila. Together, the three make up Trickpony: a self-described “unconventional prototype band” that creates sensual cyber jams with one nostalgic foot in the past and one dreamy foot in the future. Think trip-hop atmospherics, candle-lit pop, downtempo rollers and spine-tingling, hallucinatory textures. Just weeks ago, Trickpony released their divine debut EP, ‘24/7 Heaven’. Now, the trio makes its Dekmantel Festival debut.')
