  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Ben UFO & Call Super & Objekt & Pariah', 'ben ufo & call super & objekt & pariah', false, 'Yes, you read that right: four DJs, zero brakes – this is mixing as you’ve never encountered it. Ben UFO, Call Super, Objekt, and Pariah link arms for a B2B2B2B that treats the booth as a relay race. Individually, each has bent club music out of shape – Ben UFO through the restless, anything-goes logic of Hessle Audio; Call Super via emotionally charged, time-slipping productions; Objekt with forensic rhythm design and high-pressure detail; Pariah by dismantling techno and bass into sharp, functional forms. When this foursome steps up to the turntables for a Dekmantel-exclusive collaboration – never performed before – sparks are sure to fly: tempos swapped mid-flight, grooves nudged off-axis, and low-end wobblers detonated with supersonic force.', 'https://dekmantelfestival.com/artists/ben-ufo-call-super-objekt-pariah', 'festival:dekmantel-2026', 'Yes, you read that right: four DJs, zero brakes – this is mixing as you’ve never encountered it. Ben UFO, Call Super, Objekt, and Pariah link arms for a B2B2B2B that treats the booth as a relay race. Individually, each has bent club music out of shape – Ben UFO through the restless, anything-goes logic of Hessle Audio; Call Super via emotionally charged, time-slipping productions; Objekt with forensic rhythm design and high-pressure detail; Pariah by dismantling techno and bass into sharp, functional forms. When this foursome steps up to the turntables for a Dekmantel-exclusive collaboration – never performed before – sparks are sure to fly: tempos swapped mid-flight, grooves nudged off-axis, and low-end wobblers detonated with supersonic force.')
