  -- Combo bio for multi-artist set
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Parallel 9 & Richard Akingbehin', 'parallel 9 & richard akingbehin', false, 'Parallel 9 & Richard Akingbehin move through techno’s machine logic and its lingering emotional afterglow. Parallel 9 – one of Steve Rachmad’s longest-running aliases – has, since the early 1990s, crafted a richly melodic and atmospheric strain of dance music, released across a vast catalogue. His productions distil machinic soul into fluid, dubby textures and crisp, dancefloor-ready dynamics. Richard Akingbehin brings a shared sensibility shaped by soundsystem culture and politically engaged listening. As co-founder of Berlin’s Refuge Worldwide and Kynant Records, he has consistently foregrounded techno, dub, and ambient as living, interconnected practices.', 'https://dekmantelfestival.com/artists/parallel-9-richard-akingbehin', 'festival:dekmantel-2026', 'Parallel 9 & Richard Akingbehin move through techno’s machine logic and its lingering emotional afterglow. Parallel 9 – one of Steve Rachmad’s longest-running aliases – has, since the early 1990s, crafted a richly melodic and atmospheric strain of dance music, released across a vast catalogue. His productions distil machinic soul into fluid, dubby textures and crisp, dancefloor-ready dynamics. Richard Akingbehin brings a shared sensibility shaped by soundsystem culture and politically engaged listening. As co-founder of Berlin’s Refuge Worldwide and Kynant Records, he has consistently foregrounded techno, dub, and ambient as living, interconnected practices.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Interstellar Funk', 'interstellar funk', false, 'As a member of the Dekmantel family since its earliest days, Interstellar Funk has continuously revealed the many facets of his sonic world. From live performances and adventurous B2B pairings to his legendary Greenhouse closing at Dekmantel Ten, his signature is unmistakable yet always surprising Bridging dark and light, past and future, his sound is driven by razor-sharp drums and coloured by melodic synths. Over the years, he has become an essential figure in Amsterdam’s nightlife. Not only leaving his mark as a DJ and producer, but also through his recent work curating the Dekmantel label, and as one of the founders of local listening bar San Francisco.', 'https://dekmantelfestival.com/artists/interstellar-funk', 'festival:dekmantel-2026', 'As a member of the Dekmantel family since its earliest days, Interstellar Funk has continuously revealed the many facets of his sonic world. From live performances and adventurous B2B pairings to his legendary Greenhouse closing at Dekmantel Ten, his signature is unmistakable yet always surprising Bridging dark and light, past and future, his sound is driven by razor-sharp drums and coloured by melodic synths. Over the years, he has become an essential figure in Amsterdam’s nightlife. Not only leaving his mark as a DJ and producer, but also through his recent work curating the Dekmantel label, and as one of the founders of local listening bar San Francisco.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('DJ Koolt', 'dj koolt', false, 'DJ Koolt has been pivotal to the rise of his native Uruguayan scene since he began spinning in the ’90s. Firmly rooted in Montevideo, he has helped shape the city into one of the most exciting places to hear minimalist dance music. His spiritual home is Phonotheque, the club he co-founded more than a decade ago and where he continues to lay down forward-thinking selections for a devoted following. Acid, breaks and techno form the foundations of his sound, embellished in signature style with spaced-out textures, gritty industrial futurism and flashes of avant-garde electronics. Last seen at Dekmantel Festival ’25, we’re pleased to welcome this vinyl-obsessed legend back to the decks.', 'https://dekmantelfestival.com/artists/dj-koolt-2', 'festival:dekmantel-2026', 'DJ Koolt has been pivotal to the rise of his native Uruguayan scene since he began spinning in the ’90s. Firmly rooted in Montevideo, he has helped shape the city into one of the most exciting places to hear minimalist dance music. His spiritual home is Phonotheque, the club he co-founded more than a decade ago and where he continues to lay down forward-thinking selections for a devoted following. Acid, breaks and techno form the foundations of his sound, embellished in signature style with spaced-out textures, gritty industrial futurism and flashes of avant-garde electronics. Last seen at Dekmantel Festival ’25, we’re pleased to welcome this vinyl-obsessed legend back to the decks.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Jasmín', 'jasmín', false, 'If you set foot on any proper dance floor in the past year, there’s a good chance you moved to Jasmín’s ‘Bite the Hand’. A favourite among our favourite DJs, the brilliant club track catapulted the DJ – a long-time Dekmantel favourite who came up as a regular at De School – to new heights, and made her the first Dutch artist to appear on Hessle Audio. Driving, gloomy, percussive, brainy, intricate, roaring – it’s the perfect example of what Jasmín does best in both her productions and sets: elevating dance music while weaving together (sub)genres and toying with crowd expectations. This summer, she’s stepping back into the RADAR arena.', 'https://dekmantelfestival.com/artists/jasmín', 'festival:dekmantel-2026', 'If you set foot on any proper dance floor in the past year, there’s a good chance you moved to Jasmín’s ‘Bite the Hand’. A favourite among our favourite DJs, the brilliant club track catapulted the DJ – a long-time Dekmantel favourite who came up as a regular at De School – to new heights, and made her the first Dutch artist to appear on Hessle Audio. Driving, gloomy, percussive, brainy, intricate, roaring – it’s the perfect example of what Jasmín does best in both her productions and sets: elevating dance music while weaving together (sub)genres and toying with crowd expectations. This summer, she’s stepping back into the RADAR arena.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Alex Wilcox', 'alex wilcox', false, 'Originally from Dallas, Texas and now based in Berlin via Austin, LA and Detroit, Alex Wilcox channels a wide range of influences into his electronic productions. Delivering sonic whirlwinds at turbo-speed BPMs, infused with heavy doses of pop, funk, electroclash, hardcore and punk, he pushes techno into strange and unexpected territory. His boundary-stretching practice centres on vocal experimentation, whether twisting his own voice or collaborating with artists such as CATNAPP and Chippy Nonstop. Following standout EPs on labels including Mama Told Ya and trip, Alex Wilcox released his debut album on BPitch last year.', 'https://dekmantelfestival.com/artists/alex-wilcox-live', 'festival:dekmantel-2026', 'Originally from Dallas, Texas and now based in Berlin via Austin, LA and Detroit, Alex Wilcox channels a wide range of influences into his electronic productions. Delivering sonic whirlwinds at turbo-speed BPMs, infused with heavy doses of pop, funk, electroclash, hardcore and punk, he pushes techno into strange and unexpected territory. His boundary-stretching practice centres on vocal experimentation, whether twisting his own voice or collaborating with artists such as CATNAPP and Chippy Nonstop. Following standout EPs on labels including Mama Told Ya and trip, Alex Wilcox released his debut album on BPitch last year.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Dekmantel'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Verraco', 'verraco', false, 'With his monumental closing sets at The Nest (Dekmantel ’25 and Selectors ’25) still echoing in our minds, Verraco returns to the line-up in 2026 – this time taking over yet another stage. The club moniker of JP López, a DJ and producer from Medellín, Colombia, known for his distinct blend of techno, Latin-influenced tribal rhythms, hyper-electronica, IDM, and dembow-bass technology. As co-founder of the celebrated TraTraTrax label, Verraco plays a vital role in amplifying Latinx voices across contemporary dance music. His Escándaloo EP (2023) on VOAM and Breathe… Godspeed (2024) on Timedance remain among our favourite releases of recent years, and his ongoing trajectory only sharpens the sense that his appearance at Dekmantel ’26 will be something special.', 'https://dekmantelfestival.com/artists/verraco-2', 'festival:dekmantel-2026', 'With his monumental closing sets at The Nest (Dekmantel ’25 and Selectors ’25) still echoing in our minds, Verraco returns to the line-up in 2026 – this time taking over yet another stage. The club moniker of JP López, a DJ and producer from Medellín, Colombia, known for his distinct blend of techno, Latin-influenced tribal rhythms, hyper-electronica, IDM, and dembow-bass technology. As co-founder of the celebrated TraTraTrax label, Verraco plays a vital role in amplifying Latinx voices across contemporary dance music. His Escándaloo EP (2023) on VOAM and Breathe… Godspeed (2024) on Timedance remain among our favourite releases of recent years, and his ongoing trajectory only sharpens the sense that his appearance at Dekmantel ’26 will be something special.')
